window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q11"]=window.__LIBQ["tien-nghich"]["q11"]||{};window.__LIBQ["tien-nghich"]["q11"]["cotTruyen"]=[{"chuong":1214,"tieuDe":"Thức Tỉnh!","tomTat":"Trải qua mười năm, Lý Thiến Mai liên tục hy sinh máu tươi, tinh huyết tâm thần, đạo huyết nguyên thần và cả ngọc bội mệnh hồn để nuôi dưỡng tượng đá Vương Lâm, thân thể nàng suy kiệt hoàn toàn. Khi mọi thứ vẫn không đủ, nàng rời đại lục hoang dã quay về Yêu Tông đổi hồn huyết bằng cách chấp nhận điều kiện tàn khốc: một mình xông vào khe sâu nhất chiến trường dò xét thông đạo giới ngoại, nơi chắc chắn phải chết. Sư tỷ của nàng, một bà lão bạch y tu vi Toái Niết đại viên mãn, mang hồn huyết tới sơn cốc dung nhập vào tượng đá, khiến Vương Lâm lần đầu mở mắt sau mười năm hôn mê. Thức tỉnh, hắn phát hiện mình đã tiến vào cảnh giới kỳ dị gọi là Đạo cảnh, có thể nhìn thấu nguyên thần và khống chế thần thông của người khác, khiến bà lão kinh hãi khi mọi bí mật trong người bà đều bị lộ. Bà lão kể lại toàn bộ sự hy sinh của Lý Thiến Mai suốt mười năm: từ bỏ vị trí đại đệ tử Yêu Tông, bị Phá Thiên Tông khai trừ, bị sư tôn giam cầm rồi lấy cái chết ép được tự do, và cuối cùng đem tính mạng đổi hồn huyết. Vương Lâm nghe xong run rẩy, lớp da đá trên người sụp đổ kéo theo cả đại lục hoang dã vỡ thành bốn năm mảnh vì tượng đá đã hòa làm một với đại lục. Tu vi kinh thiên động địa tuôn ra, hắn bắt lấy bà lão bắt dẫn đường, quyết tâm lao tới chiến trường Yêu Tông cứu Lý Thiến Mai."},{"chuong":1215,"tieuDe":"Ngàn Vạn Người Không Ngăn Nổi!","tomTat":"Sau khi nghe bà lão bạch y kể hết mọi chuyện về Lý Thiến Mai, Vương Lâm nói bốn chữ 'Ta đi cứu nàng!' rồi bỏ qua cả nhu cầu bế quan tăng hiểu biết Đạo cảnh lẫn nguy cơ Thác Sâm phát hiện ở giới ngoại, lao đi như lưu tinh kéo theo bà lão. Hắn nhớ lại lời ly biệt của Lý Thiến Mai tại Vô Cực Tông, đau đớn vì nợ nàng mười năm. Bà lão vạch lộ trình truyền tống nhiều chặng: Hải Hồn Tông → tinh vực cấp sáu → Tiên Âm Môn → Vô Cực Tông → tinh vực cấp chín → Yêu Tông. Vương Lâm phóng xuyên tinh vực cấp hai để lại khe nứt xé đôi cả tinh vực, vượt tinh vực cấp ba tiến vào tinh vực cấp bốn. Tại đại lục Hải Hồn Tông, hắn phá vỡ đại trận phòng hộ, uy hiếp tông chủ Khuy Niết đại viên mãn mở truyền tống trận và giao nộp toàn bộ nguyên tinh — ánh mắt hắn khiến tông chủ tự phun máu mà không cần động thủ. Không kiên nhẫn chờ nửa canh giờ, Vương Lâm cưỡng ép nguyên lực kích hoạt truyền tống trận rồi cùng bà lão biến mất, trận pháp sụp đổ sau đó. Hắn để lại lời hứa bồi thường gấp mười lần."},{"chuong":1216,"tieuDe":"Uy Danh Mười Năm Trước","tomTat":"Vương Lâm cùng bà lão tóc bạc cưỡng ép ngưng tụ thiên địa nguyên lực vào truyền tống trận ở tinh vực cấp dưới để truyền tống tức thì lên tinh vực cấp sáu, phá nát truyền tống trận khi xuất hiện. Đệ tử Tiên Âm Môn trông coi trận pháp nhận ra hắn chính là Lữ Tử Hạo — kẻ tưởng đã bị Thần Tông giết mười năm trước. Vương Lâm lao tới ba đại lục Tiên Âm Môn, một chưởng phá tan toàn bộ đại trận phòng ngự mà tu sĩ Toái Niết cũng phải tốn thời gian mới phá nổi. Tông chủ tân nhiệm Tiên Âm Môn từng chứng kiến trận chiến năm xưa, không dám kháng cự, lập tức giao toàn bộ nguyên tinh và mở truyền tống trận hướng tới Vô Cực Tông. Vương Lâm thu nguyên tinh, cùng bà lão truyền tống tới tu chân tinh Vô Cực Tông tinh vực cấp tám, tuyên bố muốn lấy một thứ pháp bảo tại đây."},{"chuong":1217,"tieuDe":"Cường Giả Vi Tôn!","tomTat":"Vương Lâm quay lại Vô Cực Tông qua truyền tống trận, lao thẳng tới ngọn núi do thanh kiếm Cổ Thần hóa thành để đoạt pháp khí Cổ Thần cửu tinh nhằm cứu Lý Thiến Mai nơi chiến trường. Khi hắn kích hoạt Cổ Thần lực bên trong ngọn núi, mi tâm lần lượt tái hiện bốn Cổ Thần tinh điểm, pho tượng Cổ Thần bên trong giãy giụa gào thét, núi nứt vỡ thiên địa biến sắc. Sáu cường giả Thiên Nhân Đệ Nhất Suy của Vô Cực Tông lao tới ngăn cản: hắc y lão giả thi triển mười chín lôi cầu nhưng bị Vương Lâm giành quyền khống chế bằng một chữ «Lôi», tông chủ Vô Cực Tử dùng long kiếm tấn công nhưng bị ngàn vạn đạo kiếm khí đánh lui, hắc y lão giả phun máu. Vương Lâm cố thương lượng, hạ huyết thệ phun máu tạo ký hiệu chứa hồn phách gửi tông chủ, tiết lộ Thủy Đạo Tử giết hắn bất thành mà bị trọng thương bế quan. Hắc y lão giả chụp nát huyết thệ, thương lượng hoàn toàn thất bại. Vương Lâm lạnh lùng tuyên bố «cường giả vi tôn», chấp nhận dùng vũ lực. Bốn thái tổ trưởng lão Vô Cực Tông kéo đến trực tiếp tấn công."},{"chuong":1218,"tieuDe":"Một Câu Nói","tomTat":"Sáu trưởng lão thần thông Thiên Nhân Đệ Nhất Suy của Vô Cực Tông đồng loạt vây công Vương Lâm. Giữa trận chiến, Vương Lâm phát hiện ngọc bội mệnh hồn Lý Thiến Mai nứt thêm nửa tấc, mệnh hồn cực kỳ suy yếu, nàng đang gặp nguy cơ sinh tử. Trong cơn bức bách, Vương Lâm đột phá lên Lục tinh vương tộc Cổ Thần, tinh điểm thứ năm và thứ sáu đồng loạt hiện ra, tinh điểm thứ bảy bắt đầu hình thành. Hắn đạp sụp ngọn núi sơn môn Vô Cực Tông, thu thanh huyết kiếm Cổ Thần bị phong ấn bên trong — khi chạm vào cảm giác máu mủ tình thâm như vốn thuộc về hắn. Dồn sức mạnh Cổ Thần vào huyết kiếm chém một nhát, khiến hai trưởng lão mất nhục thân, bốn người trọng thương. Vương Lâm bay lên trời cảnh cáo Vô Cực Tông: nếu Quy Nguyên Tông bị tổn thương sẽ xóa tên Vô Cực Tông khỏi Vân Hải, rồi rời đi. Hắn ngộ ra rằng trong tu chân giới, một kiếm một câu nói mạnh hơn vạn lời hứa."},{"chuong":1219,"tieuDe":"Cái Khe Yêu Tông","tomTat":"Sau trận đánh bại sáu trưởng lão Vô Cực Tông, Vương Lâm thu huyết kiếm Cổ Thần vào mi tâm và tự đánh giá toàn diện sức mạnh hiện tại: ba thành uy lực huyết kiếm đủ chém chết Thiên Nhân Đệ Nhất Suy, chưa mở phong ấn dùng đạo thuật Đạo cảnh cũng đủ chiến ngang, nếu mở phong ấn có hy vọng đạt Toái Niết trung kỳ đối phó cả Đệ Tam Suy. Hắn xác lập mục tiêu rõ ràng: đạt Đệ Tam Bộ, giết Thủy Đạo Tử và lão tổ gia tộc thượng cổ La Thiên. Cùng lúc, Thủy Đạo Tử trong mật thất Thần Tông tầng thứ chín chịu thống khổ sinh tử mười năm, dung nhan biến đổi liên tục, đồng tử biến mất bị ánh sáng bảy màu che khuất, thề trả thù Vương Lâm và nhắc đến chủ nhân cực kỳ suy yếu. Vương Lâm khai phá tầng thứ tám, lần đầu bước vào tầng thứ chín Vân Hải tinh vực, phóng sát khí kinh động mãnh thú cấp mười hai, được lão bà áo trắng dẫn đường tới cái khe chiến trường Yêu Tông. Chương giới thiệu toàn diện Yêu Tông: tông phái thần bí nhất Vân Hải, ít môn nhân nhưng đáng sợ, tách từ Thần Tông mà không tuân lệnh, trường kỳ phòng thủ cái khe chống mãnh thú. Tại chiến trường, mấy nghìn tu sĩ đang chiến đấu, sáu cao thủ nổi bật trong đó có nữ tử lạnh như băng dùng kiếm vàng và lão già tu vi gần Đệ Nhất Suy. Ba người Yêu Tông thật sự đứng trong sương mù lam quan sát. Cuối chương, mãnh thú đồng loạt co rút, dấu hiệu vương thú xuất hiện, nữ tử lạnh như băng tuyên bố muốn giết vương thú, trong khi Vương Lâm đang ngày càng tới gần."},{"chuong":1220,"tieuDe":"Thân Ảnh Áo Trắng Trong Hồng Quang","tomTat":"Tại chiến trường khe nứt bên ngoài sáu tu chân tinh Yêu Tông, Cửu U Long — ấu long từ Cửu U Thâm Uyên, thực lực cấp mười hai, một trong sáu loài thú đồng hành thiên giai đạo thú Cát Cùng — xuất hiện. Ba tu sĩ Yêu Tông sương lam nhận dạng và truyền tin cấp báo trưởng lão. Sáu cao thủ liên thủ tấn công Cửu U Long nhưng thất bại trước đầu lâu nghìn trượng hút sức sống, bốn người bị thương nặng. Lão già tu vi cao nhất ra lệnh mấy nghìn tu sĩ hiến tế sức sống kích hoạt Yêu Tông đại trận, phong bế tạm thời khe chiến trường khiến Cửu U Long thu mình. Ba tu sĩ Yêu Tông tuyên bố sẽ tự đối phó Cửu U Long khi trận pháp hết nhưng bị gián đoạn: từ xa truyền đến tiếng gào thét kinh thiên, một đạo hồng quang ngợp trời lao tới. Bên trong có một nam tử áo trắng tóc bạc tu vi cường hãn khiến tinh không gợn sóng, phía sau có lão bà áo trắng đi theo."},{"chuong":1221,"tieuDe":"Trở Thành Vật Cưỡi Của Ta, Ta Sẽ Tha Mạng Cho Ngươi!","tomTat":"Chương giới thiệu chi tiết cấu trúc Yêu Tông với sáu tu chân tinh xếp hình tròn tạo đại trận, sáu sơn môn hoạt động độc lập, cùng truyền thuyết về tông chủ đời đầu — người theo lời đồn cũng chính là tông chủ Thần Tông, đến từ Viễn Cổ Tinh Vực, đã mất tích, hiện Thần Tông do người hầu năm xưa thay mặt điều khiển. Vương Lâm cùng Bạch Bà Tử bay từ tầng thứ hai tinh vực đến khe chiến trường, khí tức của hắn khiến mấy ngàn tu sĩ và sáu cao thủ chấn động, mãnh thú hoảng sợ. Vương Lâm vung tay tạo cuồng phong lôi đình quét sạch toàn bộ mãnh thú bên ngoài khe, nhận ra đầu lâu hắc khí mang khí tức ma đầu Tịch Diệt Giới liền há miệng hút hết. Không chờ trận pháp mở, Vương Lâm dùng hai tay xé rách khe chiến trường, Cửu U Long nghìn trượng lao ra cắn nuốt nhưng bị đánh hai chưởng — bị thương nặng và mất hai sừng. Vương Lâm giẫm lên đầu rồng yêu cầu nó làm vật cưỡi dẫn đường vào khe tìm Lý Thiến Mai."},{"chuong":1222,"tieuDe":"Đạo Thuật","tomTat":"Cửu U Long cảm nhận ba luồng khí tức trên người Vương Lâm — sức mạnh thần linh thái cổ, sức mạnh cắn nuốt hồn phách và khí tức thú hoàng Cát Cùng — rồi khuất phục dưới hai chưởng ấn, trở thành vật cưỡi. Toàn bộ tu sĩ bên ngoài khe nứt chấn động. Khi Vương Lâm định bay sâu vào khe nứt tìm Lý Thiến Mai, trưởng lão Yêu Tông tu vi Thiên Nhân Đệ Nhị Suy từ tu chân tinh ba bước dịch chuyển tinh không xuất hiện chặn đường, đòi thử tư cách. Hai bên giao đấu kịch liệt: Vương Lâm dùng sức mạnh Cổ Thần, hóa giọt máu mi tâm thành huyết kiếm chém nát pháp bảo mai rùa, rồi thu huyết kiếm vào thân hóa toàn thân thành kiếm, song chỉ tay phải phá hủy Dịch Linh Ấn hoàn chỉnh năm ký hiệu và điểm trán đánh đối thủ bay khỏi khe nứt. Trưởng lão xin dừng tay, thừa nhận là sư phụ năm xưa thu nhận Lý Thiến Mai, tặng ngọc giản bản đồ khe nứt có đánh dấu vị trí cô. Vương Lâm nhận bản đồ rồi cưỡi Cửu U Long bay sâu vào nơi tối đen. Trưởng lão kiểm tra bản thân phát hiện đạo niệm bị ngoại lực xâm nhập suy yếu — đây là đạo thuật Vương Lâm âm thầm thi triển trong lúc giao đấu; lão kinh hãi nhận ra trên thân Vương Lâm còn phong ấn chưa mở, lập tức trở về sơn môn bế quan."},{"chuong":1223,"tieuDe":"Manh Mối Của Lý Thiến Mai","tomTat":"Vương Lâm cưỡi Cửu U Long tiến sâu vào khe nứt chiến trường Yêu Tông — một thế giới tối đen khổng lồ tựa tinh không khác, chứa mấy vạn mãnh thú. Nhờ khí tức vương thú của Cửu U Long, mãnh thú không dám tới gần. Trên đường đi, hắn hồi tưởng mười năm trong Thiên Nghịch, nhờ huyết quang của Lý Thiến Mai mà không tiêu tan, từ đó tiến nhập Đạo cảnh và cảm ngộ được đạo thuật Mộng Đạo — thần thông thứ ba sau Tàn Dạ Lưu Nguyệt. Càng tiến sâu, thế giới chuyển từ đen sang tím, vào biên giới khu vực gọi là khe nứt Tử Giới, Cửu U Long run rẩy sợ hãi. Tại đây, Vương Lâm cảm nhận dao động thần thông còn sót lại — lần đầu tìm được manh mối về Lý Thiến Mai. Hắn thi triển Tuế Nguyệt Nghịch Chuyển đảo ngược thời gian, nhìn thấy ảo ảnh quá khứ: nữ tử áo lam sắc mặt nhợt nhạt, quần áo nhuốm máu, tay cầm trường kiếm, bút vàng vờn quanh, đang nhanh chóng bay đi trong hư vô."},{"chuong":1224,"tieuDe":"Tiếng Kêu Dài!","tomTat":"Vương Lâm nhận ra Lý Thiến Mai gầy yếu da bọc xương đang giao chiến với hư ảnh tiên tử trong khe nứt tím, kích động vui mừng điên cuồng. Hắn dùng thần niệm thúc Cửu U Long tiến sâu, nhưng Cửu U Long phát hiện khí tức băng hàn đáng sợ liền hoảng sợ dừng lại — nơi đây là cấm địa của nó. Vương Lâm lấy ngọc bội mệnh hồn ra thấy vết nứt lan rộng, mệnh hồn suy yếu, biết tính mạng Lý Thiến Mai nguy kịch, liền nhảy khỏi Cửu U Long tự mình xông vào. Hắn một mình tàn sát mãnh thú rùa trăm trượng, mãng xà nghìn trượng, nhện mặt người nghìn trượng bằng kiếm khí, lửa lam, lôi đình và Dịch Linh Ấn, thế như chẻ tre tiến tới cuối thông đạo. Tại vùng băng hàn sâu nhất, hắn triệu hồi hơn một vạn Văn thú từ khe nứt trữ vật giao chiến với mãnh thú bạch khí rồi tiếp tục tiến lên. Lý Thiến Mai đã dùng hết pháp bảo, trường kiếm tan vỡ, nguyên lực và đan dược cạn kiệt, chỉ còn cây bút màu vàng chống cự yếu ớt, lam quang bảo vệ sắp sụp đổ, tuyệt vọng nhắm mắt chờ chết. Ngay lúc đó, tiếng nổ kinh thiên kèm tiếng kêu dài từ xa truyền đến, nàng mở mắt không dám tin, nước mắt lại chảy xuống."},{"chuong":1225,"tieuDe":"Xông Ra!","tomTat":"Bên trong khe nứt thế giới màu tím, lam quang bảo hộ trên thân Lý Thiến Mai bị hư ảnh chiếc roi khổng lồ quất vỡ, mãnh thú lao tới tấn công nàng. Vương Lâm cảm nhận khí tức quen thuộc của Lý Thiến Mai, điên cuồng chém giết hơn vạn Văn thú mở đường máu. Hắn dùng Định Thân Thuật và Súc Địa Thành Thốn tiếp cận, tay không túm hư ảnh chiếc roi khi chỉ còn cách nàng bảy tấc, phun máu nhưng không lùi, kích phát tinh điểm Cổ Thần phá hủy chiếc roi. Lý Thiến Mai sức sống cạn kiệt, nguyên thần suy yếu, hồn phách bắt đầu tan rã, nói lời cảm ơn rồi nhắm mắt, cây bút vàng trong tay tan vỡ. Vương Lâm thi triển Tuế Nguyệt thần thông — thạch môn khổng lồ hiện ra, dòng Tuế Nguyệt chảy quanh thân nàng làm chậm quá trình tử vong nhưng phải duy trì liên tục. Hắn nhớ lại Lý Mộ Uyển năm xưa già đi trong vòng tay mình và người yêu đang ngủ trong Tị Thiên Quan. Đối mặt thêm hai hư ảnh chiếc roi và vô số mãnh thú bao vây, Vương Lâm quyết tâm mang Lý Thiến Mai xông ra, cào mi tâm mở phong ấn cấm chế phức tạp, giải phóng toàn bộ tu vi đã bị phong ấn ở Thất Thải giới hai ngàn năm trước, thể hiện tư thái cực mạnh."},{"chuong":1226,"tieuDe":"Mở Ra Phong Ấn!","tomTat":"Vương Lâm vì Lý Thiến Mai và ân nghĩa mười năm mà quyết mở phong ấn cấm chế trong cơ thể, giải phóng đạo quả từ thất thải giới đã bị áp chế suốt thời gian dài. Phong ấn sụp đổ, nguyên lực thiên địa điên cuồng chảy vào, tu vi từ Tịnh Niết đại viên mãn đột phá lên Toái Niết sơ kỳ. Hai hư ảnh chiếc roi từ hư vô tối đen lao tới tấn công — chiếc thứ nhất bị lốc xoáy đánh vỡ, chiếc thứ hai bị hắn túm lấy. Vương Lâm ngửa mặt rít gào khiến hơn trăm mãnh thú nổ tung thành sương máu, vương thú sợ hãi lùi lại. Đạo quả chưa tiêu hết, tu vi tiếp tục bạo tăng lên Toái Niết trung kỳ. Hắn ném chiếc roi đi rồi phun huyết quang hóa huyết kiếm phá hủy nó trong hư vô, tiếng kêu rên bí ẩn truyền ra. Khe nứt quỷ dị khiến Thiên Kiếp không thể giáng xuống, nếu ở bên ngoài Thiên Kiếp sẽ mạnh hơn vô số lần."},{"chuong":1227,"tieuDe":"Cấp Mười Ba","tomTat":"Vương Lâm đứng giữa biển máu nhận diện nữ tử áo đen thực chất là mãnh thú bọ cạp chín đuôi cấp mười ba đã hóa hình người, tu vi tương đương Thiên Nhân Đệ Nhất Suy, chính là thủ phạm đả thương Lý Thiến Mai. Hắn dùng huyết kiếm chém nát chín chiếc roi đuôi bọ cạp hư ảnh, rồi thi triển thần thông học từ Lỗ Phu Tử đánh ra chưởng ấn ngưng tụ thiên địa nguyên lực kết hợp sức mạnh Cổ Thần tràn ngập vạn dặm, buộc nữ tử phải phun máu phòng thủ. Nữ tử rút roi đuôi bọ cạp thực thể nhưng cũng bị huyết kiếm chặt đứt, buộc phải hiện nguyên hình bọ cạp khổng lồ vạn trượng. Vương Lâm kích hoạt tinh điểm Cổ Thần, biến thành hình thể Cổ Thần gần ngàn trượng, đánh bại hoàn toàn bọ cạp: phá nát hai càng, kéo đứt hai đuôi, quăng thân bọ cạp vào đàn mãnh thú khiến nó gần như tử vong. Chương xác nhận đây là trạng thái mạnh nhất trong hai ngàn năm tu đạo của Vương Lâm: Toái Niết trung kỳ, Cổ Thần tinh lục tinh (tinh điểm thứ bảy đã hiện hình), năm đạo bổn nguyên thức tỉnh, huyết kiếm máu Cổ Thần, đủ tư cách bá chủ một phương ở cả nội giới lẫn ngoại giới. Nữ tử bọ cạp dọa rằng Viễn Cổ Đế Phi sẽ giết toàn tộc Vương Lâm, hắn đáp lạnh lùng rằng toàn tộc đã chết, chỉ còn một mình. Sau đó Vương Lâm cầm đuôi bọ cạp làm vũ khí lao vào quét sạch đàn mãnh thú xung quanh, Văn Vương nhìn chằm chằm con bọ cạp sắp chết với vẻ khát máu."},{"chuong":1228,"tieuDe":"Tế Đàn Của Cổ Thần","tomTat":"Vương Lâm tiêu diệt bọ cạp chín đuôi cấp mười ba Tử Huyết, xé chín đuôi dung hợp thành một thu vào trữ vật, đập vỡ đầu lấy hắc đan chứa nguyên thần. Văn Vương dẫn năm nghìn Văn thú hút máu bọ cạp, tu vi tăng mạnh, rồi truy sát mãnh thú khắp khe nứt. Vương Lâm dùng thần thức lục soát ký ức bọ cạp, phát hiện khe nứt có mười chín mãnh thú hóa hình, càng sâu càng có mãnh thú cường đại, và nữ tử thần bí đang chữa thương bị giam cầm sâu bên trong. Hắn liên tưởng khe nứt này với khe nứt Phong Tiên giới nơi Văn Vương thoát ra, nảy ý dùng thiên kiếp giáng khi ra ngoài để phá đại trận Phong Giới. Khi sắp tới cửa ra, phân thân nữ tử áo hồng Y Nguyệt — phi tử viễn cổ Tiên Hoàng — bất ngờ xuất hiện, nhận ra huyết kiếm từng đả thương Tiên Hoàng và năm đạo bổn nguyên trong cơ thể Vương Lâm. Y Nguyệt đề nghị liên minh: đổi việc giúp Vương Lâm rời khe nứt cứu Lý Thiến Mai lấy hắn quay lại giúp nàng chữa thương, phần thưởng là dẫn hắn tới tế đàn Cổ Thần và kết đồng minh vĩnh viễn. Vương Lâm nhận ngọc bội truyền tống, kiểm tra an toàn rồi rời đi. Cuối chương, bản thể Y Nguyệt ngồi trong tinh thể lục giác mười trượng sâu trong khe nứt tối đen, chậm rãi mở mắt nhìn vào hư vô."},{"chuong":1229,"tieuDe":"Thiên Kiếp Giáng Xuống","tomTat":"Gần một tháng sau khi Vương Lâm tiến vào khe nứt chiến trường, khu vực bên trong trở nên quá mức yên tĩnh với mùi máu tanh liên tục tràn ra ngoài. Một lão giả đại cao thủ lẻn vào dò xét rồi quay về báo cáo: toàn bộ bên trong là thi thể mãnh thú bị phá nát gồm cả thú vương, hình thành biển máu. Các tu sĩ kinh hoàng suy đoán nguyên nhân, nhiều người không tin một mình Vương Lâm gây ra sát kiếp lớn đến vậy. Ngay sau đó, tầng mây tím cuồn cuộn bao phủ cả tinh vực cấp chín, uy áp mênh mông khiến hàng trăm tu sĩ phun máu — thiên kiếp giáng xuống. Thái thượng trưởng lão Yêu Tông lần đầu lộ diện, nhận ra đây là vô lượng kiếp — tất sát chi kiếp dành cho người bằng với thiên địa. Hắn ra lệnh mở trận pháp sơn môn, đón tất cả tu sĩ vào tu chân tinh trú ẩn. Trong tầng mây mở ra lỗ hổng thông thế giới khác, hiện ra tòa lầu các bạch ngọc với pho tượng ngồi khoanh chân và hai thanh thạch kiếm cắm trước người."},{"chuong":1230,"tieuDe":"Một Tay Che Trời","tomTat":"Thiên kiếp bùng nổ khắp tinh vực cấp chín, tiếng sấm lan tới cả tinh vực cấp tám, đại lục hoang dã sụp đổ, vô số mãnh thú chết. Vương Lâm mặc y phục đỏ đẫm máu xuất hiện từ khe nứt chiến trường Yêu Tông, tay phải che chở Lý Thiến Mai, tay trái giơ lên đỡ tia sét ngàn trượng rồi tranh đoạt quyền điều khiển lôi lực thiên địa, phản kích lôi đình oanh thẳng vào tầng mây. Ý chí của hắn theo lôi đình xâm nhập mật thất Thần Tông, kích hoạt Thất Thải Đinh tỏa sáng chói mắt khiến Thủy Đạo Tử phun máu, toàn bộ công sức ép gỡ pháp bảo uổng phí. Mộc Băng Mi bị giam mười năm trong Thần Tông bừng tỉnh từ đả tọa, Vương San San tái mặt bên cạnh. Tông chủ Phá Thiên Tông rời bế quan mở đại trận rồi hướng về khe nứt Yêu Tông. Quỷ Tông mở đại trận, hư ảnh yêu thần vạn trượng tham lam hút lực lượng kỳ dị từ tầng mây. Vương Lâm nhìn xuyên tầng mây thấy lầu các bạch ngọc với pho tượng và hai thanh thạch kiếm ở thế giới bên kia, nhận định thiên kiếp chưa đủ phá đại trận Phong Giới. Thanh thạch kiếm thứ nhất phóng khí xanh hóa hư kiếm tấn công, Vương Lâm dùng kiếm khí hư ảnh hươu chống đỡ, hư kiếm suy yếu nhưng thạch kiếm nứt vỡ phóng ra trường kiếm xanh thật sự lao về phía hắn."},{"chuong":1231,"tieuDe":"Phong Giới Đại Trận","tomTat":"Huyết kiếm đã hấp thu máu mãnh thú trong thế giới khe nứt xuất hiện trong tay Vương Lâm, lần lượt đối đầu bốn thanh kiếm thiên kiếp (xanh, lam, đen, vàng) vỡ ra từ thạch kiếm trước pho tượng trên lầu các bạch ngọc mà không hề suy xuyển. Vương Lâm rạch Cổ Thần tinh điểm lấy giọt máu Cổ Thần lực tiếp cho huyết kiếm, triệu hồi hư ảnh hình người đẩy lùi ba kiếm. Bốn kiếm thiên kiếp xoay tròn tạo dòng xoáy chứa thế giới hỗn độn, phát tiếng gọi mê hoặc hứa trường sinh thoát luân hồi, hút hàng trăm tu sĩ Yêu Tông cùng tu sĩ Thần Tông, Phá Thiên Tông biến mất. Vương Lâm là người ứng kiếp nên cảm thụ mạnh hơn — tiếng nói biến thành giọng phụ mẫu, Lý Mộ Uyển, Vương Bình, Chu Tước lão Thánh Hoàng — nhưng đạo tâm kiên cố không lay động. Dòng xoáy tiêu tán vào tầng mây ngưng tụ thành núi mây tím khổng lồ có phù văn chữ đạo đè xuống. Chờ đúng lúc thiên kiếp triển khai toàn bộ uy lực, Vương Lâm dùng huyết kiếm xé tinh không phía dưới, kết hợp tu vi và áp lực núi mây mở khe nứt vào hư vô nơi Phong Giới Đại Trận. Bước vào hư vô, hóa thành lạc ấn, dùng thân chống đỡ núi mây, phun máu truyền lực thiên kiếp lên đại trận dạng lưới — trở thành người đầu tiên từ cổ chí kim mượn thiên kiếp phá phong ấn Phong Giới."},{"chuong":1232,"tieuDe":"Cửu Cung Bát Quái","tomTat":"Vương Lâm triệu hư ảnh Cổ Thần truyền lực vào Phong Giới đại trận, kích phát hào quang bảy màu biến ảo thành trường thương bạch ngọc xuyên thấu núi mây Thiên Kiếp, lộ ra bốn thanh bảo kiếm bên trong. Hắn phun máu vì thương thế nhưng kiên định, nhớ lại tiếng gào không cam lòng của tu sĩ giới nội chết trên Phong Giới đại trận từ xưa, khơi dậy huyết tính. Khe nứt tinh không xé rộng, pho tượng trên lầu các bạch ngọc tỉnh dậy — tay phải biến từ đá thành máu thịt, hô Cửu Cung Vô Lượng phát chín tinh cầu Cửu Cung Phong Ấn giáng xuống. Chín thiên thạch cổ đại nhập thể Vương Lâm qua chín đốm máu, cố ngưng tụ ở ngực để phong ấn. Vương Lâm hóa Lục tinh Cổ Thần cao nghìn trượng, giấu Lý Thiến Mai trên người, dùng sức Cổ Thần ngăn ngưng tụ và tuyên bố mình là Cổ Thần không phải tiên. Pho tượng tiếp tục phát động Bát Quái Ấn mạnh hơn Cửu Cung, tám ký hiệu tạo vòng tròn biến hóa đè xuống khiến Vương Lâm buộc phải lui bước. Trong tình thế nguy cấp, hắn bình tĩnh gọi chủ nhân Phong Giới xuất hiện, tiết lộ đã bí mật đưa người này tới đây từ trước."},{"chuong":1233,"tieuDe":"Thiên Kiếp Là Kiếp, Chỉ Vì Tạo Hóa","tomTat":"Vương Lâm truyền thần niệm kích hoạt Thiên Nghịch Châu, từ bên trong nguyên thần biến ảo ra ngọc bội của chủ nhân Phong Giới (Tông Chủ) bay khỏi cơ thể, khiến Bát Quái Thiên Kiếp chấn động. Thái thượng trưởng lão Yêu Tông Huyền Bỉnh nhận ra ngọc bội, phá khai đại trận xuất hiện. Ngọc bội biến ảo ra cây đại thụ chọc trời hiện mặt người Tông Chủ, lần lượt ra mệnh lệnh: giao Huyền Bỉnh dùng đạo khí sửa sang Vân Hải Tinh Vực và đi tìm Nam Vân Tử, Hồng Sam Tử, Chiến Tiên Tử để hợp nhất Tứ Đại Tiên Giới Phong Vũ Lôi Điện chuẩn bị đại chiến giới ngoại; lệnh Thủy Đạo Tử toàn lực trợ giúp Yêu Tông; nhắc Cổ Yêu thực hiện ước định năm đó. Tông Chủ hé lộ bản chất Thiên Kiếp cho Vương Lâm: đến từ thái cổ, từ thiên đạo sinh tử, hiện tại chỉ là Tiểu Kiếp. Ngọc bội hóa tinh quang phá giải Phong Giới Đại Trận. Vương Lâm nhớ lời Thanh Thủy về Cực Cảnh, liều mạng để Bát Quái dung nhập cơ thể nhờ thân Cổ Thần chống chịu. Thiên Kiếp tiếp tục giáng Thất Tinh Bắc Đẩu sát kiếp, Bát Hoang Phong Thiên Trận phong tỏa mọi đường lui, và Ngũ Hành vô lượng năm thủ ấn khổng lồ lao tới."},{"chuong":1234,"tieuDe":"Cực Cảnh Sinh Ra","tomTat":"Vương Lâm ngộ ra bản chất thiên kiếp diễn biến từ chín tới một, tầng tầng hợp nhất cuối cùng thành thiên cực kiếp — Cực Cảnh. Hắn từ chối thái thượng trưởng lão Yêu Tông trợ giúp, tuyên bố phải tự mình đối kháng. Bị Thất Tinh đánh trọng thương, nguyên thần sụp đổ nhưng khóa chặt, chủ động nuốt hỏa chưởng ấn Ngũ Hành để tái tạo nguyên thần, dùng Ly hỏa và Chấn lôi phản kháng. Tứ Tượng thiên kiếp triệu tứ linh, Vương Lâm thu phục Chu Tước nhập thể, hỏa diễm gần đạt hư hỏa chỉ kém một đường. Tam Tài giáng xuống xuyên thấu mi tâm, ngực, tứ chi. Lưỡng Nghi hóa Thái Cực phát nổ bao trùm toàn thân, thân Cổ Thần lục tinh huyết nhục mơ hồ — Lý Thiến Mai được bảo vệ không tổn thương. Cuối cùng Nhất Kiếp tuyên vô lượng kiếp bắt đầu, Cửu Cung tới Lưỡng Nghi đồng loạt xuất hiện sinh ra Cực Cảnh, đồng thời Cực Cảnh cũng sinh ra bên trong cơ thể Vương Lâm."},{"chuong":1235,"tieuDe":"Thôn Linh Phệ Thể Tuyệt Thiên Đại Pháp!","tomTat":"Trong vô lượng kiếp, chín thiên thạch Cửu Cung biến ảo xếp thành đồ án chồng lớp từ Bát Quái tới Thái Cực đồ, cuối cùng sinh ra Cực Cảnh — đồng thời cơ thể Vương Lâm cũng tái sinh Cực Cảnh đã mất ngàn năm, tóc bạc chuyển đỏ, thân ngừng sụp đổ. Vương Lâm dùng hai đạo Cực Cảnh kết hợp sợi tơ xanh của chủ nhân Phong Giới phá một lỗ hổng nhỏ trên Phong Giới Đại Trận, thu nhỏ thân Cổ Thần ôm Lý Thiến Mai lao ra Thái Cổ Tinh Thần — chính thức đặt chân vào giới ngoại. Ngay khi thoát ra, Khai Thiên Phủ phản chủ lao theo chém xuyên ngực Vương Lâm gây trọng thương cực nặng, rồi dung nhập Phong Giới Đại Trận biến mất, lỗ hổng khép lại với sợi tơ xanh kết rễ. Đối diện mấy trăm tu sĩ giới ngoại xông tới giết, Vương Lâm nhớ lời nguyền của tiền bối Thất Thải Giới, lần đầu thi triển tiên thuật Thôn Linh Phệ Thể Tuyệt Thiên do Thanh Thủy truyền — bắt quyết điểm ngực, hóa sương mù đen nuốt sạch tinh hoa tu sĩ để chữa thương, bắt đầu tàn sát."},{"chuong":1236,"tieuDe":"Thác Sâm","tomTat":"Vương Lâm ẩn trong sương mù đen, dùng Thôn Linh Phệ Thể Tuyệt Thiên điên cuồng thôn phệ mấy trăm tu sĩ giới ngoại đang thủ trận tại Phong Giới Đại Trận. Lão giả Toái Niết đại viên mãn chỉ huy kết trận, thi triển thần thông ngũ sắc và tấm khiên mặt quỷ chống đỡ nhưng bị tia chớp đỏ xuyên phá tất cả, nguyên thần diệt tuyệt, xác hóa tro. Vương Lâm tiếp tục thôn phệ liên tục, hóa sương mù thành dòng xoáy hút tu sĩ chạy xa trở lại, quét sạch toàn bộ không còn sống sót. Tu vi cấp tốc khôi phục, nguyên thần no đủ, nhưng vết thương ngực vẫn chậm lành. Cảm giác thôn phệ giống ăn tiên quả, gây mê muội không nỡ dừng — hắn lộ dấu hiệu ma hóa rõ ràng, bị tu sĩ giới ngoại gọi là ma. Chương nhắc lại hàng ngàn năm trước, tiên nhân giới nội cố phá Phong Giới Đại Trận thoát ra nhưng bị trận linh giết chết, giới ngoại lạnh lùng đứng nhìn — tiên nhân trước khi chết thề đời sau sẽ phá trận khiến giới ngoại vạn linh tuyệt diệt. Cuối chương Vương Lâm cảm ứng nguy hiểm, thôn phệ nốt tu sĩ rồi dùng súc địa thành thốn biến mất, ngay lúc đó một thân ảnh khổng lồ sánh với tinh không gầm thét tên Vương Lâm lao tới."},{"chuong":1237,"tieuDe":"Truy Sát","tomTat":"Vương Lâm dung nhập trời đất thoát khỏi tầm mắt Thác Sâm ở giới ngoại Thái Cổ Tinh Thần. Thác Sâm đã đồ sát bộ lạc thái cổ suốt mười năm nên bị ba cao thủ bước thứ ba (một người cảnh giới Không Niết) truy sát, bị thương nghiêm trọng và yếu đi nhiều. Thác Sâm cảm nhận khí tức Vương Lâm, xé tinh không đuổi theo, hai bên đối đầu ngắn ngủi — Vương Lâm dùng Cực Cảnh (thiên kiếp cực) tấn công, tia chớp đỏ chui vào cơ thể Thác Sâm phá hoại liên tục, nhưng bị Thác Sâm phản đòn đánh trúng, phun máu, vết thương ngực chứa khí tức Khai Thiên Phủ lại toạc ra. Ba cao thủ bước thứ ba kịp thời ép tới ngăn Thác Sâm truy kích, Vương Lâm thoát được. Sau khi bình tĩnh lại, Vương Lâm xác định mục tiêu đưa Lý Thiến Mai tới chỗ Lam Mộng Đạo Tôn — ngũ đại tôn giả Thái Cổ Tinh Thần ở Lam Sơn (Lam Ti Tộc). Hắn quyết tâm giết tu sĩ giới ngoại chuẩn bị cho đại chiến hai giới, tấn công Ma Nạp Tinh, dùng sương đen nuốt toàn bộ tu sĩ, dùng thuật Định và Cực Cảnh hạ lão giả áo xanh lục (thiên nhân đệ nhất suy) mạnh nhất trên tinh."},{"chuong":1238,"tieuDe":"Liên Hệ","tomTat":"Vương Lâm hiện thân trên tu chân tinh, dùng sương đen diệt gần như toàn bộ tu sĩ ngoại giới, sau đó thi triển Trừu Tinh Hồn Lực rút tinh hồn toàn hành tinh. Hắn tiếp tục bay qua nhiều tu chân tinh khác thu tổng cộng bảy đám khí tinh hồn, nguyên thần hồi phục gần hết, chỉ còn vết thương do Khai Thiên Phủ vẫn chưa lành. Nhận định chỉ sức mạnh Cổ Thần mới bức được khí tức Khai Thiên Phủ, hắn quyết định hướng tới Nguyệt Tộc — thế lực Cổ Thần duy nhất hắn biết trong Thái Cổ Tinh Thần, đồng thời tính kế dẫn Thác Sâm đến nếu bị truy kích. Vương Lâm hồi tưởng toàn bộ cục diện nội-ngoại giới: Phong Giới Đại Trận hấp thụ hương hỏa khiến nội giới thiếu tu sĩ bước thứ ba, Chủ nhân Phong Giới bị Thủy Đạo Tử đánh lén và Chưởng Tôn liên thủ trọng thương, rồi chọn dung nhập vào Phong Giới Đại Trận biến nó thành vật nội giới. Chủ nhân Phong Giới nhìn thấy năm đạo bổn nguyên trên người Vương Lâm mà nhận làm truyền nhân, giao sứ mệnh thống lĩnh nội giới chống ngoại giới. Vương Lâm khẳng định Thái Cổ Tinh Thần không thuộc về hắn, hắn từ nội giới đến. Cùng lúc, Thác Sâm xé khe tinh không lao ra, bị ba cao thủ bước thứ ba Thái Cổ Tinh Thần truy sát mười năm; nhận ra không giết ba người này thì không thể cắn nuốt Vương Lâm, hắn hóa Cổ Thần khổng lồ quay đầu tuyên chiến."},{"chuong":1239,"tieuDe":"Trận Chiến Định Mệnh","tomTat":"Thác Sâm không tiếc cho nổ một tinh điểm để thoát khỏi ba cao thủ Viễn Cổ Tinh Thần truy sát, phong ấn nữ tử Không Niết rồi xé tinh không đuổi theo Vương Lâm. Hai cao thủ còn lại nhận thưởng lục phẩm đạo linh từ một nữ tử áo trắng bí ẩn mang khí tức Tiên Vực, người này sau đó lặng lẽ đi theo hướng Thác Sâm truy đuổi. Vương Lâm chủ động dẫn Thác Sâm vào lãnh địa Nguyệt Tộc, hóa thân Cổ Thần ngàn trượng giao phong chính diện, dùng huyết kiếm, Thần Quyền, Dịch Linh Ấn và lời uy hiếp về Đồ Ti thức tỉnh để chặn đứng ý định thôn phệ của Thác Sâm. Nguyệt Tộc chớp thời cơ kích hoạt Phong Thần Đại Trận chuẩn bị vô số vạn năm cùng hàng loạt chí bảo chuyên trị Cổ Thần, phong ấn cả hai bên. Vương Lâm thuyết phục Thác Sâm tạm hợp tác, cùng thi triển Cổ Thần Bát Tinh thuật Hư quét sạch pháp bảo Nguyệt Tộc, nhưng bị đốt xương ngón tay Cổ Thần gần cửu tinh đánh vỡ ký hiệu khiến cả hai trọng thương. Vương Lâm thi triển Thôn Linh Phệ Tuyệt Thiên nuốt hơn ba vạn tộc nhân khôi phục thương thế, rồi dùng Cổ Thần lực đã bí mật hút giữ từ Thác Sâm để thi triển thần thông Dòng chảy tinh thần, chém đứt ngón trỏ Thác Sâm bằng huyết kiếm và chẻ đôi đốt xương Cổ Thần khiến lực trùng kích quét ngang toàn trường. Nữ tu bước thứ ba phong ấn trong mi tâm Thác Sâm đột nhiên bộc phát ánh sáng chói mắt khiến hắn hoảng hốt bỏ chạy với một nửa đốt xương, còn Vương Lâm dùng Côn Cực Tiên cuốn bắt nguyên thần lão giả tóc bạc Nguyệt Tộc, mang theo nửa đốt xương còn lại rời khỏi tinh vực Nguyệt Tộc với thu hoạch khổng lồ."},{"chuong":1240,"tieuDe":"Đưa Nàng Cho Ta","tomTat":"Vương Lâm thoát khỏi cuộc đuổi giết của Thác Sâm sau khi mi tâm hắn dị biến tỏa sáng chói mắt khiến Thác Sâm bỏ chạy. Hắn lảo đảo xuất hiện trong tinh không Thái Cổ Tinh Thần, lấy Lý Thiến Mai ra từ khe trữ vật, dùng Tuế Nguyệt thần thông duy trì sinh cơ cho nàng đang sắp tiêu tán. Thu nửa đốt xương ngón tay Cổ Thần và dùng Côn Cực Tiên phong ấn lão giả tóc bạc vào trữ vật. Ôm Lý Thiến Mai bay xuyên tinh không hướng về Lam Ti tinh vực tìm Lam Mộng Đạo Tôn cứu chữa, nhớ lại lời hứa năm xưa với nàng và với Lý Mộ Uyển. Lam Ti tộc được giới thiệu lịch sử: tộc lạc tóc lam từng bị áp bức làm sủng cơ, sau được Lam Mộng Đạo Tôn quật khởi trở thành đại tộc. Lam Mộng Đạo Tôn — ngũ tôn Thái Cổ Tinh Thần, si tình chỉ yêu một nữ tử — gảy cổ cầm trên Lam Sơn, khẳng định với em gái người yêu rằng tỷ tỷ chưa chết. Bạch y nữ tử theo Vương Lâm tới bờ tinh vực Lam Ti tộc nhưng bị Lam Mộng Đạo Tôn chặn xua đuổi bằng ý cảnh tuyệt sát, nàng cảnh cáo rằng Vương Lâm đã bị lựa chọn rồi và sẽ phải đi ra. Cuối chương Vương Lâm ôm Lý Thiến Mai tới Lam Ti tinh vực, ánh sáng lam tràn ra và có tiếng nói trầm thấp vang vọng."},{"chuong":1241,"tieuDe":"Nối Lại…","tomTat":"Lam Mộng Đạo Tôn xuất hiện trong ánh lam quang, vung tay áo tạo gió lốc cướp lấy Lý Thiến Mai từ tay Vương Lâm rồi biến mất, từ đầu đến cuối không thèm liếc hắn một cái. Vương Lâm nhận ra giọng nói này chính là kẻ đã gây tai ương cho hắn ở Thất Thải Giới năm xưa, và đoán chắc Đạo Tôn là phụ thân của Lý Thiến Mai, có cách khiến nàng tỉnh lại. Hắn bay vào tu chân tinh của Lam Mộng Đạo Tôn, vận toàn bộ nguyên lực và Cổ Thần lực đối kháng trận pháp cấm chế kinh thiên trên Lam Sơn, leo bậc thang suốt ba ngày đêm, mồ hôi lẫn máu, mạch máu gần nổ tung, chỉ để nhìn thấy Lý Thiến Mai lần cuối trước khi rời đi. Trên đỉnh núi, Lam Mộng Đạo Tôn đã trục hết hắc khí từ thất khiếu Lý Thiến Mai, nàng khôi phục dung mạo và tỉnh lại, nhưng mất toàn bộ trí nhớ, tự xưng là Lam Nguyệt và hỏi Vương Lâm là ai. Vương Lâm đau khổ đáp tên mình rồi buông bỏ sự chống cự, bị lực cản đẩy tung khỏi đỉnh núi, khoảng cách kéo ra vô tận. Lam Nguyệt dù quên hết nhưng mơ hồ cảm thấy đau lòng và quen thuộc khi nhìn hắn bay đi, hỏi phụ thân tại sao lại có cảm giác đó. Lam Mộng Đạo Tôn nói khoảng cách xa nhất trên đời là lãng quên, đoạn tình cảm này vốn sai lầm, nhưng nếu sau khi mất trí nhớ mà hai người vẫn bắt đầu lại được thì hắn tuyệt sẽ không ngăn cản, dù phải đánh một trận với viễn cổ tiên vực."},{"chuong":1242,"tieuDe":"Bạch Y Nữ Tử","tomTat":"Vương Lâm rời Lam Sơn một mình trong tâm trạng bi thương, để Lý Thiến Mai ở lại. Khi Na Di tới biên giới tinh vực Lam Ti tộc, hắn bất ngờ cảm nhận nguy cơ sinh tử mãnh liệt chưa từng có kể từ Thủy Đạo Tử. Hắn thi triển ánh mắt ác mộng bằng năm đạo bổn nguyên trong đồng tử ở trình độ gần tới vô hạn, phát hiện một bạch y nữ tử không có sinh cơ tung bay trong tinh không, thần thức không thể cảm nhận, ánh sáng che kín tướng mạo. Sau khi đả tọa bảy ngày phân tích, Vương Lâm nhận ra nữ tử đã bám theo hắn từ sau khi gặp Thác Sâm, chỉ dừng ở ranh giới Lam Ti tộc. Hắn phát hiện thân thể mình đã biến hóa nhờ leo Lam Sơn: nguyên lực tăng, Cổ Thần lực hùng hậu hơn, nguyên thần linh hồn nhạy cảm hơn nhiều, và suy đoán Lam Mộng Đạo Tôn dùng cách gián tiếp ám chỉ cảnh báo vì không thể nói thẳng. Vương Lâm quyết định ở lại tu chân tinh thổ nạp một tháng, khôi phục tu vi tới đỉnh phong. Cuối chương, Lam Mộng Đạo Tôn hiện thân trong ánh sáng lam nhu hòa, hỏi Vương Lâm có muốn học chín đại thần thông của mình không."},{"chuong":1243,"tieuDe":"Lựa Chọn","tomTat":"Lam Mộng Đạo Tôn đưa ra hấp dẫn cực lớn cho Vương Lâm: truyền toàn bộ pháp thuật cả đời (chín thức thần thông, sáu thức tiên pháp, ba thức đạo thuật, một thức sinh tử), hương hỏa hai ngàn triệu môn đồ, năm đạo khí thiên thạch thiên ngoại, giúp thân thể Cổ Thần đại thành và bảy đạo bổn nguyên đại thành. Đổi lại hai điều kiện: ăn vong tâm quả phát thề thoát ly giới nội trở thành người Thái Cổ Tinh Thần, và cắt đứt tình cảm giới nội kết đạo lữ với nữ nhi duy nhất Nguyệt Nhi. Vương Lâm nhớ tới tiên nhân hy sinh trong Phong Giới Đại Trận và lời hứa cả đời với Lý Mộ Uyển, dứt khoát cự tuyệt. Hắn phản vấn Lam Mộng về người trọng yếu nhất, khiến đối phương trầm mặc, rồi chỉ ra giới nội tồn tại lực lượng khiến chưởng tôn hoảng sợ — Lam Mộng thừa nhận. Lam Mộng tiết lộ bước thứ ba tu đạo gồm tứ cảnh Không (Không Niết, Không Linh, Không Huyền, Không Kiếp), chưa ai độ kiếp Không Kiếp thành công, bản thân có hai đạo bổn nguyên ở mức Không Huyền đỉnh phong, giới ngoại ít nhất bảy người ngang hàng. Cuối cùng Lam Mộng không cưỡng cầu, xóa nhân quả và truyền cho Vương Lâm ba thức thần thông: Phiên Thiên Ấn (lật thiên địa đồ diệt vạn linh), thuật phòng ngự ánh sáng (cảm ngộ Không Linh), và thức thứ ba — một trong tam đại đạo thuật — chương kết thúc trước khi thi triển."},{"chuong":1244,"tieuDe":"Dung","tomTat":"Lam Mộng Đạo Tôn truyền thức thứ ba cho Vương Lâm — Dung biến đạo thuật, thần thông dung hợp thay đổi bổn nguyên bản thân, biểu diễn biến mây thành băng kiếm bảy thước. Vương Lâm thi triển Hô Phong đạo và Vũ đạo để Lam Mộng dung hợp giúp thành một giới phòng hộ, Hô Phong che trời Hóa Vũ phủ đất, lực phòng hộ tương đương Quang ảnh thuẫn. Lam Mộng xác nhận đây là lục đạo tam trọng thuật của tiên đế Bạch Phàm, Chí tôn Lôi giới. Trước khi rời đi, Lam Mộng Đạo Tôn bày tỏ quyết tâm: sẵn sàng phản bội Lam Ti tộc và Thái Cổ Tinh Thần nếu giúp nàng khôi phục trí nhớ. Vương Lâm bế quan bốn tháng trên đỉnh núi tu chân tinh, ngồi bất động dưới mưa gió sấm chớp, cuối cùng lĩnh ngộ thành công Phiên Thiên Ấn — lật trời thành đất, uy lực hủy thiên diệt địa vượt xa mọi thần thông cũ. Hắn còn nhận ra Phiên Thiên Ấn có biến thức nghịch chuyển da và nội tạng thân thể, sát thương mạnh hơn vô số lần. Lam Mộng Đạo Tôn trên Lam Sơn kinh ngạc vì người có năm đạo bổn nguyên chỉ mất bốn tháng đã học xong, trong khi hắn tưởng phải mất mấy năm."},{"chuong":1245,"tieuDe":"Bức Tường Ngăn Cách Bước Thứ Ba","tomTat":"Trên tu chân tinh Lam Ti Tộc, sau mùa mưa nửa năm chuyển sang mùa đông lạnh giá, Vương Lâm vẫn khoanh chân ngồi trên đỉnh núi phủ tuyết cảm ngộ tam đại thần thông. Sau khi đã hiểu Phiên Thiên Ấn, hắn dành bốn tháng lần mò Quang Ảnh Thuẫn — tản thần thức bao trùm toàn bộ tu chân tinh, nhìn thấy ánh sáng (sức sống) từ vạn vật ngưng tụ quanh thân hóa quang ảnh khổng lồ, nhưng chưa hoàn toàn minh ngộ do cảm nhận được bức tường ngăn cách — chính là cửa ải tiến vào bước thứ ba. Vương Lâm chuyển sang cảm ngộ đạo thuật dung hợp ẩn trong tiểu cầu lốc xoáy, dùng năm đạo bổn nguyên hấp thu hết khí bên trong cho đến khi tiểu cầu hoàn toàn tiêu tan. Hắn lần đầu thi triển đạo thuật dung hợp lên thanh kiếm băng, biến kiếm thành mảnh băng, nước mưa, sương mù rồi đám mây trắng bay đi. Vương Lâm quyết định dung hợp Súc Địa Thành Thốn trước để khắc phục khuyết điểm không thi triển được khi nguyên lực rối loạn. Hắn xác nhận kế hoạch cần hương hỏa Hỏa Tước Tộc và sấm sét Thiểm Lôi Tộc để năm đạo bổn nguyên đại thành, nhận ra ấn ký Thái Cổ Tinh Thần trên mi tâm có thể cắn nuốt lẫn nhau tiến hóa, và dự định tra nguyên thần trưởng lão Nguyệt Tộc để biết Chưởng Tôn thuộc bộ tộc thái cổ nào."},{"chuong":1246,"tieuDe":"Dị Biến!","tomTat":"Sau mấy tháng nhập định trên đỉnh núi Lam Ti Tộc, Vương Lâm dung hợp thành công Súc Địa Thành Thốn với cơ thể, lấy bản thân làm trời đất để bù sơ hở khi thiên địa nguyên lực hỗn loạn, nhưng nhược điểm mới là tiêu hao nguyên lực nhiều, chỉ thi triển liên tục hơn mười lần phải bổ sung. Hắn rà soát toàn bộ thần thông bình sinh và nảy ý dung hợp thêm Rải Đậu Thành Binh vào Hô Phong Hoán Vũ. Vương Lâm thử ép dung hợp Phong Tiên Ấn vào tiểu cầu lốc xoáy Hô Phong Hoán Vũ nhưng hai thứ bài xích dữ dội gây bùng nổ kinh thiên, hắn dùng Súc Địa Thành Thốn mang vụ nổ ra biên giới tinh vực rồi kích hoạt Quang Ảnh Thuẫn phản xạ sức hủy diệt để thoát hiểm. Không cam lòng, hắn đổi phương pháp: bóp nát tiểu cầu mở ra giới ngàn trượng Hô Phong Hoán Vũ rồi đưa Phong Tiên Ấn vào, nhưng sức bài xích vẫn khiến Phong Tiên Ấn nứt rạn rồi sụp đổ tan thành từng mảnh. Dị biến bất ngờ xảy ra: cấm chế bên trong Phong Tiên Ấn dung nhập vào giới hình thành một vùng thiên địa, vô số chiến hồn tản ra hóa tinh quang rơi vào từng mảnh vỡ, khiến Vương Lâm ngây người."},{"chuong":1247,"tieuDe":"Hương Hỏa","tomTat":"Giới ngàn trượng co rút dung nhập vào cơ thể Vương Lâm, hoàn thành dung hợp Hô Phong Hoán Vũ. Trở về tu chân tinh, hắn phát hiện chiến hồn trên các đại lục trôi nổi trong giới tản ra khí tức trắng sữa — hương hỏa thật sự — dung nhập năm đạo bổn nguyên. Vương Lâm nhận ra chuỗi nhân quả tạo hương hỏa: mảnh vỡ Lôi Tiên Giới qua Thiên Kiếp luyện hóa, dùng Rải Đậu Thành Binh tạo mười tám tầng địa ngục thu hồn phách, Lam Mộng Đạo Tôn trợ giúp dung hợp thành một giới mở ra cơ hội. Hắn lấy nửa đốt ngón tay Cổ Thần ra thử dùng tinh điểm hấp thụ nhưng thất bại vì ý chí bên trong chống lại. Sau đó lấy nguyên thần lão già tóc bạc Nguyệt Tộc từ Côn Cực Tiên, dùng huyết kiếm tra tấn suốt mấy canh giờ hút tinh khí, rồi dùng thần thức khai thác ký ức thần thuật và hủy diệt hoàn toàn. Hồn phách lão già hiện ra trong giới, tản ra hương hỏa kinh người. Từ ký ức, biết Nguyệt Tộc còn ba bộ lạc và một lão tổ tông bước thứ ba đang bế quan trị thương. Vương Lâm quyết định rời đi vì nữ tử áo trắng Lam Ti Tộc vẫn đợi bên ngoài."},{"chuong":1248,"tieuDe":"Ra Khỏi Lam Ti!","tomTat":"Vương Lâm khai thác trí nhớ lão già đốt ngón tay Cổ Thần, biết được Nguyệt Tộc vốn là Nô Tộc của Cổ Thần, nổi loạn nhờ đám người thần bí trợ giúp tự xưng Nguyệt Phệ Tộc, được truyền Thanh Vân Linh Thuật và Linh Chủng để hấp thụ sức mạnh Cổ Thần mà phát triển thành đại tộc. Thu đốt ngón tay Cổ Thần vào khe trữ vật rồi rời tinh vực Lam Ti Tộc bằng Súc Địa Thành Thốn. Nữ tử áo trắng đã đợi sẵn ngoài tinh không, hai lần phá gợn sóng Thuấn Di phong tỏa Vương Lâm, dùng bàn tay hư ảo bắt giữ rồi tự xưng Lan Phi, Lâu Lan, Viễn Cổ Bát Phi, lộ dung mạo trùng khớp Lý Mộ Uyển. Vương Lâm cố ý giả hoảng hốt để dụ nàng lộ mục đích hấp thu thần tính Cổ Thần, rồi bùng Hô Phong Hoán Vũ Giới đẩy lùi nàng ngàn trượng, dùng huyết kiếm phá bàn tay hư ảo thoát vây, thu lại làn khói vàng thần tính. Vương Lâm nhận ra nàng chỉ là phân thân, tuyên bố bản thể tới mới không địch nổi, rồi thi triển Phiên Thiên Ấn nghịch chuyển tinh không phản kích."},{"chuong":1249,"tieuDe":"Hình Chiếu Phân Thân","tomTat":"Vương Lâm thi triển Phiên Thiên Ấn của Lam Mộng Đạo Tôn lần đầu trong thực chiến, tạo thiên địa hư ảnh nghịch chuyển đè bẹp Bạch Y Nữ Tử, phá sụp phòng hộ ban đầu của nàng. Hắn lạnh lùng phân tích đối phương chỉ là hình chiếu phân thân tu vi thiên nhân tam suy, không phải thực thể hay tu sĩ Đệ Tam Bộ, đồng thời tố cáo nàng dùng ảo thuật ảnh hưởng tâm thần. Hắn tung chiến hồn trong Hô Phong Hoán Vũ giới tấn công ồ ạt, nữ tử thi triển Thiên Linh Quang phá giới nhưng không thương tổn chiến hồn, ngưng hắc quang thành trường kiếm đen tấn công nhưng bị Quang Ảnh Thuẫn phản chiết xạ ngược. Vương Lâm rút huyết kiếm chém nứt ngọc bội nữ tử khiến nàng phun máu bỏ chạy, phân thân có máu tươi khiến hắn sửng sốt. Nữ tử tuyệt vọng kêu cứu bổn tôn, từ ngọc bội hiện ra cánh tay trắng như ngọc ấn ngón tay xuống với uy lực vượt cả Thủy Đạo Tử, khiến Vương Lâm cảm nhận nguy cơ sinh tử mãnh liệt. Ngón tay xuyên phá Quang Ảnh Thuẫn hoàn toàn, đụng vào Hô Phong Hoán Vũ giới khiến chiến hồn kêu thê lương, khí tức trắng sữa lan ra đối kháng. Trận chiến kết thúc ở thế cliffhanger, tình huống cực kỳ nguy hiểm cho Vương Lâm."},{"chuong":1250,"tieuDe":"Truy Sát","tomTat":"Ngón tay triệu hồi bổn tôn của Bạch Y Nữ Tử phá vỡ Quang Ảnh Thuẫn và ấn lõm Hô Phong Hoán Vũ giới, Vương Lâm rút đốt xương Cổ Thần chắn đỡ, bị một tia lực xuyên ngực nhưng nhờ thân Cổ Thần hồi phục tức khắc. Vương Lâm phản kích bằng huyết kiếm chém đứt cánh tay triệu hồi, ngọc bội Bạch Y Nữ Tử vỡ tan, cắt đứt kết nối bổn tôn. Thế cục đảo ngược hoàn toàn, Vương Lâm dung nhập thiên địa truy sát nữ tử liên tục trong Thái Cổ Tinh Thần, thi triển lôi đình cắt đường rồi Phiên Thiên Ấn đánh trúng, huyết kiếm đâm xuyên hậu tâm. Lúc bị thương nặng, không gian quanh thân nữ tử hiện hình ảnh cảnh quỳ trước cánh tay trắng nõn, từ thiên linh phóng ra lực hương hỏa môn đồ nồng đậm vượt ba thành Hô Phong Hoán Vũ giới với tia sáng vàng bên trong. Nữ tử chạy tới tinh vực Ma Hạt Tộc tự xưng là một trong những phân thân của Lan Phi, sai mấy ngàn tu sĩ dùng mạng ngăn cản, nhưng Vương Lâm hóa thân Cổ Thần ngàn trượng dùng Quang Ảnh phản xạ mọi thần thông khiến tu sĩ chết thương vô số, một quyền tạo khe nứt tinh không bức nữ tử hiện hình."},{"chuong":1251,"tieuDe":"Âm Mưu","tomTat":"Trong lúc Vương Lâm truy sát, ấn ký mi tâm Bạch Y Nữ Tử kích hoạt, hé lộ ký ức nàng từng là thánh nữ bộ tộc bị biến thành phân thân nuôi dưỡng hình chiếu và cánh cửa hương hỏa cho một thực thể bí ẩn. Khí tức trắng sữa bùng lên giúp nàng thoát đi bằng na di tới phía đông Thái Cổ Tinh Thần, thân thể dần trong suốt sắp biến mất. Vương Lâm truy kích kịp, thi triển Định Thần Thuật đóng băng trời đất, dùng bổn nguyên lực kéo nàng ra khỏi hư vô rồi dùng huyết kiếm đâm thiên linh phá nguyên thần, đoạt hồn phách cùng hương hỏa. Khi Bạch Y Nữ Tử chết, một đạo kim tuyến phân thân của Lan Phi từ trong thi thể lao vào hư vô, huyết kiếm chém không trúng vì kim tuyến phi vật chất. Ngân Y Nữ Thi bất ngờ tự thoát khỏi khe trữ vật, tùy ý kéo kim tuyến đã biến mất trong hư vô quay lại rồi nuốt vào thất khiếu, thể hiện sức mạnh vượt xa Vương Lâm. Trước khi quay vào khe trữ vật, Ngân Y Nữ Thi cảnh báo rằng hương hỏa là một âm mưu rất lớn, nàng dường như vì nó mà mất đi hết thảy, hoàn toàn trái ngược với những gì các cường giả từng nói về hương hỏa là mấu chốt bước thứ ba. Vương Lâm chấn động trầm tư, tự nhủ cả đời tu đạo chưa bao giờ dựa vào môn đồ hương hỏa, quyết tâm cảnh giác, rồi nhắm tới Thiểm Lôi Tộc nơi không có tu sĩ Đệ Tam Bộ nhưng sở hữu đạo thiểm điện vạn năm bất diệt, định nuốt thánh vật này để lôi bổn nguyên tiến thêm bước lớn."},{"chuong":1252,"tieuDe":"Đoạt Xá","tomTat":"Vương Lâm đứng ngoài tinh vực Thiểm Lôi Tộc — một lôi trì khổng lồ tràn ngập sấm sét trong Thái Cổ Tinh Thần. Nhờ đã hấp thụ sấm sét pho tượng ở thế giới bảy màu, nuốt Đạo quả và ngộ lôi bản nguyên, hắn chậm rãi xâm nhập lôi trì mà sấm sét không thể gây hại. Tiến vào sâu nhất, hắn khoanh chân thổ nạp, khí tức hoàn toàn tiêu tán, dung hợp hoàn toàn với lôi trì trở thành một phần của nó. Ký hiệu tia chớp từ mắt phải phóng ra xuyên lôi trì, tất cả sấm sét nhường đường chỉ phương hướng. Thiểm Lôi Tộc được giới thiệu là bộ tộc hùng mạnh với mười sáu tu chân tinh xếp vòng tròn, trung tâm là đại lục Vân Tàn — thánh địa có miếu thờ bị tia chớp đen đánh liên tục vài ngàn năm. Trên tu chân tinh màu vàng, một thanh niên hắc y tộc nhân Thiểm Lôi Tộc bị thương nặng, tuyệt vọng oán hận thân phận, trước khi chết tự kéo ký hiệu tộc trên mi tâm ra ngoài. Tia chớp của Vương Lâm phát hiện thanh niên này và phóng thẳng vào vết thương mi tâm, thực hiện đoạt xá thân xác."},{"chuong":1253,"tieuDe":"Thiểm Lôi Bảng","tomTat":"Một phần nguyên thần Vương Lâm đoạt xá thành công thân thể Vu Phi — thanh niên hắc y Thiểm Lôi Tộc đang hấp hối, trong khi bản thể vẫn ở lôi vực dung nhập lôi trì. Qua ký ức Vu Phi, hắn biết đây là tộc nhân tầm thường bị tu sĩ Nguyên Anh sơ kỳ Tề Trì cướp mất động phủ truyền thừa và hút tu vi. Vương Lâm nhận ra hệ thống tu luyện Thái Cổ Tinh Thần dựa trên ký hiệu mi tâm bắt nguồn từ sấm sét bất diệt, còn ký hiệu do hắn tự sinh ra có cấp độ cao hơn rất nhiều. Trên đường đến động phủ, hắn chỉ bằng ánh mắt phá vỡ Kim Đan ba tu sĩ Kết Đan dám khinh nhờn. Xâm nhập động phủ Tề Trì, hắn dễ dàng đánh bại lão Nguyên Anh, dùng Sưu Thần Thuật lục ký ức, lấy hết bảo vật nhưng không giết vì luật tộc cấm chém giết sinh tử. Từ ký ức Tề Trì, Vương Lâm nắm được hệ thống Lôi Tinh và Thiểm Lôi Bảng: mỗi trăm năm tám trăm người trên mười ba tu chân tinh tranh đoạt một suất duy nhất vào thánh địa tiếp xúc sấm sét bất diệt, cuộc tranh đoạt tiếp theo chỉ còn bảy năm. Hắn quyết định dùng danh tính Vu Phi tích lũy Lôi Tinh để quang minh chính đại giành suất vào thánh địa, nhưng ngay lúc đó đội của Tộc Quyền thuộc Thiên Lôi Tông gồm một Nguyên Anh trung kỳ cùng ba Kết Đan đang phóng đến cướp bảo vật động phủ này."},{"chuong":1254,"tieuDe":"Vì Tiền Bối","tomTat":"Vương Lâm trong động phủ Tề Trì bóp vỡ Lôi quả hấp thu sấm sét vào nguyên thần, nhận ra một quả đổi được một khối Lôi Tinh. Khâu Đức Hải — một trong tứ đại trưởng lão Nguyên Anh Thiên Lôi Tông — dẫn ba tu sĩ Kết Đan đến đòi cống nạp pháp bảo đan dược cho tông chủ tiến vào Thiểm Lôi Bảng. Vương Lâm bước ra bùng uy áp, phá ký hiệu mi tâm ba Kết Đan khiến Kim Đan vỡ, cướp pháp bảo. Khâu Đức Hải đẩy đồng đội làm vật cản bỏ chạy, thuấn di hơn mười lần gần mười vạn dặm, bóp nát ngọc giản cầu cứu. Lần lượt ba đồng môn Nguyên Anh Thiên Lôi Tông nhập bọn chạy trốn. Vương Lâm ép cả bốn trưởng lão dẫn đường về sơn môn, tại đó vung tay phá ký hiệu mi tâm cả bốn, cướp sạch bảo vật ném bốn người xuống quảng trường. Từ đại điện phóng ra một tu sĩ Hóa Thần sơ kỳ gầy gò xấu xí, cuồng nhiệt sùng bái Vương Lâm, tự nguyện dâng pháp bảo xin làm tôi tớ, khiến Vương Lâm sửng sốt nhớ tới Hứa Lập Quốc."},{"chuong":1255,"tieuDe":"Kình Địch","tomTat":"Chung Đại Hồng, tông chủ Thiên Lôi Tông, dùng kỹ thuật nịnh hót bảo toàn tu vi trước Vương Lâm, giao nộp toàn bộ vật phẩm đổi Lôi tinh gồm cành cây Lôi quang, đan dược tử quang và phi kiếm sắc bén. Vương Lâm gọi Hứa Lập Quốc ra khỏi túi trữ vật, truyền thần niệm giao nhiệm vụ cướp vật đổi Lôi tinh trên lãnh thổ Thiểm Lôi Tộc. Vương Lâm tặng Hàm Hồn đan cho Chung Đại Hồng để buộc hắn sưu tập vật phẩm, tính kế không dùng đan dược mình đổi trực tiếp vì sẽ tăng thực lực cho Thiểm Lôi Tộc. Hứa Lập Quốc và Chung Đại Hồng nhận ra nhau cùng tu luyện pháp thuật nịnh hót, coi nhau là kình địch. Hứa Lập Quốc ghen tức, nảy ý dùng Lưu Kim Bưu đi giết Chung Đại Hồng, lộ nụ cười âm hiểm."},{"chuong":1256,"tieuDe":"Thế Này Mới Là Sống Chứ!","tomTat":"Vương Lâm ở lại Thiên Lôi Tông một tháng thổ nạp, sai Hứa Lập Quốc và Chung Đại Hồng lấy Thiên Lôi Tông làm trung tâm quét bốn phía thu gom vật phẩm, đã gom được gần mười vạn Lôi tinh. Hứa Lập Quốc được thả ra ngoài, hưng phấn thu phục gần trăm tu sĩ Thiểm Lôi Tộc, bắt họ chế ngai vàng trăm trượng khiêng đi, bốn nữ tu và bốn thanh niên hầu hạ, sai người gào khẩu hiệu, tận hưởng cuộc sống đế vương sau hai ngàn năm bị Vương Lâm sai khiến. Hứa Lập Quốc thi triển kiếm khí phá tan trận pháp sương đen của lão quái Nguyên Anh hậu kỳ, thu phục đối phương, nghe tin tông phái Lôi Tiên Đạo có tông chủ xinh đẹp tuyệt trần liền dẫn đoàn tiến quân cướp người đoạt bảo. Chung Đại Hồng được Vương Lâm ban phi kiếm và đan dược, chiến lực tăng mạnh, cẩn thận vơ vét vật phẩm ở hướng khác, coi Hứa Lập Quốc là kình địch cả đời. Cuối chương Vương Lâm nghiên cứu ngọc giản chứa công pháp Tụ Lôi Ấn của Thiểm Lôi Tộc, mục đích thật sự là điều tra tộc ấn vì mơ hồ cảm giác việc hấp thu sấm sét bất diệt cực kỳ quan trọng."},{"chuong":1257,"tieuDe":"Một Suy Đoán Đáng Sợ","tomTat":"Vương Lâm lĩnh ngộ công pháp Tụ Lôi Ấn từ ngọc giản Thiểm Lôi Tộc, thử thi triển nén sấm sét ba vạn lần đạt cực hạn thân thể Vu Phi, nhận xét nguyên thần hắn đã thành sấm sét vượt cả lão tổ Thiên Nhân Ngũ Suy. Sau hơn một tháng nghiên cứu tộc ấn trên mi tâm thân thể Vu Phi, hắn phát hiện bên trong ký hiệu ẩn giấu một ý chí ngủ say có thể hấp thu sấm sét từ tộc nhân — cơ chế cực kỳ giống Môn Đồ Hương Hỏa, tộc nhân thực chất dâng tính mạng và sấm sét cho sấm sét bất diệt. Mở rộng suy đoán, hắn cho rằng toàn bộ Thái Cổ Tinh Thần có thể là vùng nuôi dưỡng của một tồn tại tu vi siêu việt, liên hệ đến thế giới Thủy Đạo Tử chứa hai mươi tỷ môn đồ, đại trận Phong giới, lời Ngân Y Nữ Tử về hương khói có độc và Lam Mộng Đạo Tôn bị tiếng rống người Nội giới trọng thương. Hắn kiên quyết tuyệt đối không tu luyện hương hỏa. Vài ngày sau Chung Đại Hồng trở về trước Hứa Lập Quốc, dâng đống vật phẩm đổi Lôi tinh, được Vương Lâm ban một viên thuốc, đề nghị đi đến Lôi Tinh Điện sắp mở cửa để đổi Lôi tinh."},{"chuong":1258,"tieuDe":"Lôi Tinh Điện","tomTat":"Vương Lâm cùng Chung Đại Hồng phi hành hơn nửa thống đến vùng trung tâm tu chân tinh để đến Lôi Tinh Điện — nơi tộc nhân Thiểm Lôi Tộc đổi vật phẩm lấy Lôi tinh, mỗi năm chỉ mở ba ngày. Trên đường đi, Chung Đại Hồng nịnh hót chu đáo, đổi cách xưng hô thành 'chủ tử' theo kiểu Hứa Lập Quốc, chủ động vơ vét vật phẩm đổi Lôi tinh của kẻ gặp trên đường rồi nộp hết cho Vương Lâm. Hắc Ma Pháp Vương — tu sĩ Vấn Đỉnh sơ kỳ đỉnh phong, hạng 766 Thiểm Lôi Bảng — phóng ngang qua nhưng chỉ bị Vương Lâm quét mắt liền run rẩy toàn thân, vã mồ hôi lạnh, vội phóng đi. Tại khe nứt sương mù dẫn vào Lôi Tinh Điện, hai tu sĩ áo đỏ tu vi Âm Hư canh gác. Tu sĩ Khuy Niết Chu Thiên Tử xuất hiện từ mây sấm sét, tuyên bố nhắm nhóm ba mươi Thiểm Lôi Bảng, thưởng đan dược cho lính canh rồi tiến vào. Vương Lâm và Chung Đại Hồng bước vào khe nứt mà không bị phát hiện bất thường. Khi tiến vào, Vương Lâm nhìn chằm chằm sương mù xanh bốn phía, trong mắt bùng ra ánh sáng kỳ dị, dường như phát hiện điều gì đó đặc biệt về sương mù."},{"chuong":1259,"tieuDe":"Chính Thức Tiến Lên Thiểm Lôi Bảng","tomTat":"Vương Lâm cùng Chung Đại Hồng đi qua khe nứt sương mù sấm sét dẫn đến Lôi Tinh Điện. Trong khe nứt, Vương Lâm nhận ra sương mù thực chất là sấm sét hóa thành bằng thuật đại thần thông, lợi dụng cấu trúc bộc lộ để dùng thần thức sấm sét xâm nhập thôi diễn ngược lại, học được tuyệt học thất truyền Hóa Lôi Vi Vụ của Thiểm Lôi Tộc — là người đầu tiên trong lịch sử làm được. Ra khỏi khe nứt, Chung Đại Hồng giới thiệu ba cửa của Lôi Tinh Điện; Vương Lâm dùng thần thức quét thấy tầng không gian thứ tư có chín cường giả đang thổ nạp. Vào cửa đông, Vương Lâm che giấu tu vi thành Vấn Đỉnh trước mặt ba lão già canh ao, ném lượng lớn vật phẩm vào ao đen suốt nửa ngày đổi Lôi tinh bằng ngọc giản mệnh hồn của Vu Phi. Tên Vu Phi chính thức xuất hiện trên Thiểm Lôi Bảng ở vị trí 799 với bốn mươi sáu vạn bốn ngàn Lôi tinh, gây xôn xao tộc nhân trên mười ba tu chân tinh."},{"chuong":1260,"tieuDe":"Bí Mật Thiểm Lôi Tộc","tomTat":"Vương Lâm định rời Lôi Tinh Điện thì được ba lão già Dương Thực cửa đông tặng tạo hóa theo quy củ dành cho người mới lên Thiểm Lôi Bảng: Tụ Lôi Hoàn nén 8900 lần, ngọc giản công pháp Thiểm Lôi Tộc mở rộng tộc ấn, và ngọc giản lôi quang để nhận nhiệm vụ cửa tây. Lão già thứ ba tiết lộ bí mật Lôi Lục Đạo — sấm sét chia làm sáu loại, bảo Vương Lâm đi nhận nhiệm vụ Linh Niệm Lôi. Vương Lâm chuyển sang cửa tây, kiểm tra ngọc giản sáng nhất và phát hiện bí mật kinh hoàng: tổ tiên Thiểm Lôi Tộc cùng Đệ Tam Bộ đại năng tạo ra bảy trăm vạn thế giới chứa sinh linh tu luyện, tộc nhân đóng vai thiên đạo giáng thiên kiếp hủy diệt tu sĩ Hóa Thần đỉnh phong, tu sĩ thiên tài ngưng tụ Linh Niệm Lôi khi độ kiếp thực chất bị hình thần câu diệt. Vương Lâm nhận ra người tự xưng Thiên Đạo gặp khi chiến đấu với Vọng Nguyệt chính là tộc nhân Thiểm Lôi Tộc, nhưng vẫn quyết tâm hấp thu sấm sét bất diệt. Khi Vương Lâm định chộp ngọc giản nhiệm vụ Linh Niệm Lôi, Chu Thiên Tử ở gần hơn chộp trước và quát Cút với uy áp Khuy Niết, Vương Lâm lóe sát ý trong mắt."},{"chuong":1261,"tieuDe":"Giết Chu Thiên Tử","tomTat":"Vương Lâm dùng thân phận Vu Phi đưa ngọc giản cho lão tu sĩ cửa Tây Lôi Tinh Điện, được lão xin Chu Thiên Tử nể mặt cho vào bảy trăm vạn thiên địa tu luyện. Chu Thiên Tử khinh thường Vương Lâm vì tưởng chỉ là tu sĩ Vấn Đỉnh, quyết định để hắn vào bảy trăm vạn thiên địa rồi giết ở trong đó vì nơi đó có cấm chế chặn thần thức. Chu Thiên Tử tiến vào trước, suy tính giao dịch với Hạo Côn Tử. Vương Lâm theo sau, phá nát tất cả không gian loạn lưu trên đường, ung dung đuổi kịp Chu Thiên Tử. Chu Thiên Tử toàn lực hóa Lôi Long tấn công nhưng bị Vương Lâm phá tan chỉ bằng một vung tay, lộ tu vi vượt xa Toái Niết. Chu Thiên Tử hồn bay phách lạn bỏ chạy. Bản nguyên chiến ý của Chiến Tinh Dã được khẳng định đã ăn sâu vào gốc rễ tâm thần Vương Lâm."},{"chuong":1262,"tieuDe":"Không Có Ý Tốt","tomTat":"Chu Thiên Tử bỏ chạy về phía cửa ra vào bảy trăm vạn thiên địa nhưng bị Vương Lâm chặn lại, dùng thần thông qua ánh mắt kích nổ toàn bộ sấm sét trong cơ thể lão, phá tan thân xác. Nguyên thần trọng thương của Chu Thiên Tử được tộc ấn bảo vệ xông ra nhưng bị hút ngược, cầu xin tha mạng, kịp nhìn thấy hồn phách bị phong ấn trong cơ thể trong suốt của Vương Lâm và kêu lên trước khi bị bóp nát nguyên thần, hình thần câu diệt. Vương Lâm hấp thu sấm sét và lấy tộc ấn, sau đó phá cửa tiến vào bảy trăm vạn thiên địa — trọng địa Thiểm Lôi Tộc — trở thành người ngoài đầu tiên xâm nhập kể từ đám tu sĩ thần bí năm xưa. Mạo danh Vu Phi, Vương Lâm dùng ngọc giản tộc qua kiểm tra của tu sĩ Âm Hư, nhận linh phù, ngọc giản hướng dẫn và Linh Niệm Lôi. Vương Lâm nghiên cứu Linh Niệm Lôi, nhận ra nó giống sinh linh chứa ý niệm sinh cơ, cần thu thập đủ một ngàn luồng mới thành niệm lôi hoàn chỉnh, mỗi người cả đời chỉ có một cơ hội. Tu sĩ Vấn Đỉnh trung kỳ Trương Cảnh Vân — kẻ chuyên cướp Linh Niệm Lôi và hại mạng người mới — chủ động tiếp cận dụ dỗ Vương Lâm, nhưng Vương Lâm nhìn thấu ý đồ và giả vờ đồng ý, bị dẫn đến tổ hơn mười người trước trận pháp khổng lồ."},{"chuong":1263,"tieuDe":"Đây Là Thiên Kiếp Sao?","tomTat":"Trương Cảnh Vân dẫn Vương Lâm (danh giả Vu Phi) đến giới thiệu với nhóm bốn tu sĩ, thực chất là bọn lừa đảo chuyên thu niệm lôi của người mới. Bốn tên truyền âm bàn mưu, dựa vào Triệu tiền bối tu vi Âm Hư, định gộp niệm lôi thành Linh Niệm Lôi đổi phi kiếm tiên phẩm tại Lôi Tinh Điện. Vương Lâm nhìn rõ tâm tư giả tạo của chúng nhưng không thèm quan tâm. Cả nhóm tiến vào trận pháp, truyền tống đến thiên địa nơi lão tu sĩ Vi Lỗ Bị đang nghênh đón thiên kiếp. Kiếp vân ngưng tụ bao phủ bầu trời, trên đó xuất hiện mười hư ảnh Tiên nhân — Vương Lâm là một trong số đó. Trương Cảnh Vân xin đóng vai thiên đạo, hưng phấn điều khiển sáu luồng sấm sét đánh xuống Vi Lỗ Bị. Vi Lỗ Bị phun máu, rống lên tiếng cuối rồi hình thần câu diệt. Khi nghe tu sĩ họ Chu giải thích sấm sét mạnh dần là để buộc tu sĩ sinh ra Linh Niệm Lôi, Vương Lâm tâm thần rung động mãnh liệt, nhận ra thiên kiếp hắn từng trải qua cũng đều do tu sĩ Lôi Tiên Giới hóa thân thiên đạo mà giáng xuống."},{"chuong":1264,"tieuDe":"Ta Chính Là Thiên Kiếp","tomTat":"Trương Cảnh Vân bước vào kiếp vân, tiếc nuối rằng lão già Hóa Thần đỉnh phong vừa chết không sinh ra Linh Niệm Lôi, lộ ra mục đích thật sự của thiên kiếp giả là kích thích tu sĩ sinh Linh Niệm Lôi. Hắn khinh thường tấn công Vương Lâm bằng sấm sét giả thiên kiếp nhưng bị Vương Lâm vung tay siết chết, hình thần câu diệt. Vương Lâm tuyên bố mình chính là thiên đạo của bọn họ, dùng Cực Cảnh phóng tia chớp hồng sắc từ mắt lần lượt giết sạch ba tu sĩ Vấn Đỉnh và tu sĩ Âm Hư, không ai trốn thoát hay tự bạo được. Hắn xác nhận cực cảnh chính là thiên kiếp, dù thân đoạt xá có rất ít vẫn thi triển được. Thi thể tu sĩ Âm Hư rơi xuống trước mặt mấy ngàn tu sĩ phàm, tiên khí tiêu tán, Vương Lâm nói đây chính là Tiên nhân trong mắt các ngươi rồi biến mất. Tán Linh Thượng Nhân — thanh niên đầu trọc tu vi mơ hồ đạt Tịnh Niết — xuất hiện lấy thi thể, nhận xét Vương Lâm có lẽ không phải nô lệ của sấm sét. Ngoài bảy trăm vạn thiên địa, Hứa Lập Quốc tiếp tục điên cuồng vơ vét trên tu chân tinh, ngai vàng mở rộng lên năm trăm trượng, bị một nữ tu tướng mạo tuyệt vời mắng hắn chỉ là khí linh và đe dọa diệt sạch cả chủ nhân."},{"chuong":1265,"tieuDe":"Con Đường Lôi Tu Đại Năng","tomTat":"Vương Lâm bóp nát hơn mười tộc ấn Thiểm Lôi Tộc, dung hợp gần ngàn luồng Linh Niệm Lôi thành một luồng hoàn chỉnh hình quả cầu khói. Linh Niệm Lôi tự phóng xuyên mắt phải nhập nguyên thần, kích hoạt ký ức lôi bản nguyên từ thuở thiên địa sơ khai, tiết lộ lôi thực tế có Cửu đạo chứ không phải Lục đạo. Vương Lâm minh ngộ con đường tu luyện: hấp thu đủ chín loại sấm sét cộng lôi bản nguyên thành mười viên mãn thì đại thành, có thể đột phá Đệ Nhị Bộ lên Đệ Tam Bộ đại năng. Mắt phải xuất hiện tia chớp thứ hai nhỏ hơn vờn quanh ký hiệu gốc, lôi bản nguyên dần tăng trưởng. Quyết định không giết tu sĩ độ kiếp mà giết tộc nhân Thiểm Lôi Tộc đoạt niệm lôi, hóa gió bão sấm sét vạn trượng tàn sát hơn ngàn tu sĩ Thiểm Lôi Tộc trong vài ngày, thu bốn luồng lôi niệm hoàn chỉnh. Ngày thứ tư linh phù cảm ứng có người muốn độ kiếp gần đó nhưng đã có tu sĩ khác đến trước, Vương Lâm cầm linh phù thuấn di về phía đó."},{"chuong":1266,"tieuDe":"Mồi Nhử","tomTat":"Vương Lâm dùng kế mồi nhử: lợi dụng một người đàn ông trung niên tu vi Hóa Thần đỉnh phong đang chờ thiên kiếp để dụ Tiên nhân Thiểm Lôi Tộc đến qua lỗ hổng trên kiếp vân. Tiên nhân Khuy Niết hậu kỳ đại viên mãn đầu tiên xuất hiện bị Vương Lâm giết bằng một ngón tay điểm ót, hình thần câu diệt, tộc ấn bị thu. Vương Lâm bóp nát hạt châu lôi quang của lão, mắt phải hấp thu năm luồng niệm lôi. Trong nửa canh giờ tiếp theo, hơn một trăm tộc nhân Thiểm Lôi Tộc lục tục phóng xuống đều bị giết. Một tu sĩ Toái Niết dùng thuật phân thân bỏ chạy cũng bị Vương Lâm dùng tia chớp đỏ cực cảnh hủy diệt nguyên thần. Hiện tại Vương Lâm không phải bản thể nên không có cực cảnh trong người, chỉ dựa tu vi Toái Niết nhưng có thể triệu hồi cực cảnh hóa tia chớp đỏ. Cuối chương, Vương Lâm phát hiện Tán Linh Thượng Nhân ẩn trong hư không theo dõi, ép hắn lộ diện và yêu cầu giải thích lý do."},{"chuong":1267,"tieuDe":"Tán Linh Thượng Nhân","tomTat":"Vương Lâm phát hiện thanh niên đầu láng bám đuôi mình, liền phóng tia chớp hồng sắc xuyên mi tâm đối phương để kích hoạt bản thể thật ẩn bên trong. Linh hồn cực mạnh hiện ra, xưng là Tán Linh thượng nhân, tồn tại hơn vài vạn năm, tu vi đạt Toái Niết, sở hữu 971 phân thân người thường chứa tu vi để tránh thiên kiếp. Tán Linh kể lại lai lịch: năm xưa hắn nghi ngờ bản chất Tiên nhân, bị đại trưởng lão Thiểm Lôi Tộc phế tu vi nhưng giữ mạng nhằm tăng cơ hội sinh Linh Niệm Lôi. Hắn tự sáng tạo thuật Tán Linh, chia tu vi vào phân thân rồi lặp chu trình hợp-tán, từ Hóa Thần tu lên Toái Niết qua hàng vạn năm. Qua quá trình quan sát thiên kiếp và tận mắt thấy thi thể Tiên nhân thối rữa, Tán Linh phát hiện chân tướng kinh thiên: bảy trăm vạn thiên địa chỉ là lao ngục do kẻ khác tạo ra để sưu tập Linh Niệm Lôi, mọi sinh mạng bên trong chẳng qua là kiến hôi. Tán Linh đề nghị giao dịch với Vương Lâm, mời hắn cùng đến tận cùng thế giới, quyết tâm phá vỡ lao ngục bước vào tinh không."},{"chuong":1268,"tieuDe":"Tận Cùng Thiên Địa","tomTat":"Tán Linh Thượng Nhân kể cho Vương Lâm toàn bộ chân tướng bảy trăm vạn thiên địa: nơi đây là ngục tù do Thiểm Lôi Tộc tạo ra, tu sĩ bị nuôi như súc vật, thiên đạo và thiên kiếp chỉ là nhiệm vụ thu hoạch Linh Niệm Lôi khi tu sĩ đạt Hóa Thần, mọi giai thoại tiên giới đều giả. Hắn kể hành trình phát hiện chân tướng: phá phòng hộ tu chân tinh thấy tinh không, giết tu sĩ Thiểm Lôi Tộc rồi biết sự thật, sợ hãi trốn chạy đến tận cùng thế giới nơi có bức tường ngăn cách khổng lồ, rồi quyết tâm phản kháng. Hắn quay về lập Tán Linh Tông dùng phân thân truyền bá, tu luyện vài ngàn năm đạt Thiên Nhân Tứ Suy nhưng vẫn không thắng đại trưởng lão Thiên Nhân Ngũ Suy. Tán Linh cầu xin Vương Lâm liên thủ với nhiều điều kiện, Vương Lâm đồng ý vì muốn giúp người này phá vỡ ngục tù. Tán Linh tự hủy mấy vạn phân thân ngưng tụ thành linh phù huyết sắc trao cho Vương Lâm để sau này mở đường vào bảy trăm vạn thiên địa. Vương Lâm nhận linh phù rồi phóng về quảng trường trung tâm, cưỡng bức xé rách trận pháp truyền tống đang vận chuyển để tiến vào, gây kinh hoàng cho tu sĩ Thiểm Lôi Tộc."},{"chuong":1269,"tieuDe":"Chủ Nhân Ở Đâu!","tomTat":"Hứa Lập Quốc (kiếm linh) bắt cóc con nuôi xinh đẹp của một cường giả Toái Niết viên mãn Thiểm Lôi Tộc làm con tin, hóa thành sương đen bỏ chạy trong lãnh địa Thiểm Lôi Tộc. Lão già áo xanh — trưởng lão Tịnh Niết Thiểm Lôi Tộc — truy kích kịch liệt bằng lôi cầu màu đen từ tộc ấn, Hứa Lập Quốc dùng cô gái làm lá chắn và liên tục chửi bới khiêu khích để câu giờ. Cha nuôi cô gái (Toái Niết viên mãn) xuất hiện, đánh tan thân thể Hứa Lập Quốc thành nhiều mảnh rồi liên tục tra tấn bằng cách làm tan rã rồi khôi phục, Hứa Lập Quốc gần như diệt vong. Trong lúc tuyệt vọng, Hứa Lập Quốc kêu gọi chủ nhân. Vương Lâm xuất hiện giữa sấm sét trên bầu trời, tuyên bố là chủ nhân của Hứa Lập Quốc. Khi lão già áo xanh vô tình ngăn cản Hứa Lập Quốc, Vương Lâm điểm lên mi tâm lão khiến thân thể tan vỡ và nguyên thần diệt vong chỉ bằng một chỉ, thể hiện sức mạnh áp đảo. Cường giả Toái Niết viên mãn khiếp sợ, giữ chặt cô gái muốn bỏ trốn."},{"chuong":1270,"tieuDe":"Cuộc Chiến Trên Thiểm Lôi Tộc","tomTat":"Vương Lâm giết liên tiếp hai tu sĩ Toái Niết rồi xông thẳng vào thánh địa Thiểm Lôi Tộc, hút sấm sét từ cơ thể mấy trăm tộc nhân và đánh bại lão già hắc y Thiên Nhân Đệ Nhất Suy, buộc đại trưởng lão Thiên Nhân Đệ Ngũ Suy phải hiện thân nghênh chiến. Hắn dùng thân làm mồi dẫn đại trưởng lão vào lôi vực, nơi bản thể đang ẩn tu thức tỉnh hợp nhất với nguyên thần, rồi tung lôi quyền hai vạn trượng kết hợp lực lượng Cổ Thần phá nát bảo vật Lôi Sát Kính. Hai bên so Tụ Lôi Ấn, lôi cầu bốn trăm vạn lần nén của Vương Lâm đối đầu năm trăm vạn lần nén của đại trưởng lão, lực trùng kích kinh thiên khiến lôi vực mở rộng trăm lần. Vương Lâm bị trọng thương nhưng triển khai Quang Ảnh Thuẫn đánh ngược lực trùng kích, phản công bằng huyết kiếm cùng cực cảnh, ép đại trưởng lão phải xé phong ấn cuối cùng bùng tu vi Đệ Ngũ Suy để sống sót. Đại trưởng lão triệu hoán tám hồn phách Thái Cổ Lôi Long từ Thái Cổ Lôi Giới bao vây Vương Lâm, nhưng Côn Cực Tiên bị phá vỡ lớp ngoài lộ ra bản thể kim quang Vạn Giới Phong Hồn Tiên, chém đôi hồn phách tám con lôi long. Vương Lâm thi triển Thôn Hồn nuốt toàn bộ hồn phách tám Thái Cổ Lôi Long, nguyên thần tiến hóa thành lôi nguyên thần viên mãn với lôi bản nguyên tăng mạnh hơn mười lần, rồi tạo bảy vạn tầng lưới sấm sét tự khôi phục ngăn chặn truy kích. Đại trưởng lão thi triển Sinh Mệnh Thần Thông hy sinh năm trăm năm thọ nguyên rút sấm sét bất diệt phá tan lưới, Vương Lâm bóp nát linh phù rút vào hắc động hướng về bảy trăm vạn thiên địa, đại trưởng lão quyết đoán lao theo đuổi vào bên trong."},{"chuong":1271,"tieuDe":"Thất Kiếm Trảm Thiên Sơn","tomTat":"Vương Lâm dụ đại trưởng lão Thiểm Lôi Tộc vào bảy trăm vạn thiên địa, cùng Tán Linh Thượng Nhân phá tan sấm sét bất diệt rồi liên thủ vây công hắn. Trước những thần thông lôi đình được đánh đổi bằng thọ nguyên của đại trưởng lão, Tán Linh tự hủy toàn bộ ký hiệu, còn Vương Lâm rút lực hương hỏa từ các hồn phách trong Hô Phong Hoán Vũ để phá vỡ Lục Đạo Thần Lôi. Tán Linh sau đó kích hoạt Tuyệt Thiên trận, biến ý chí và sinh mệnh của hàng tỷ sinh linh thành phong ấn ngăn cách ngoại giới, đồng thời ngưng tụ Trảm Thiên kiếm giao cho Vương Lâm. Mỗi nhát kiếm Vương Lâm chém xuống đều lấy đi vô số sinh mạng, nhưng cũng lần lượt phá hủy chiến giáp truyền thừa, sấm sét âm dương và Nam Đẩu thuật của đối phương. Đại trưởng lão bị đánh nổ nửa thân dưới, hoảng sợ tháo chạy và tìm cách tái tạo thân thể, song Vương Lâm quyết không để nguyên thần hắn mang theo vạn giới phong hồn tiên trốn thoát. Bất chấp phản phệ khiến máu thịt và xương cốt chấn động dữ dội, Vương Lâm vẫn chém ra kiếm thứ sáu, làm biên giới tinh không nứt vỡ và đẩy toàn bộ bảy trăm vạn thiên địa đến sát bờ sụp đổ."},{"chuong":1272,"tieuDe":"Thất Kiếm Trảm Thiên Sơn (Cuối)","tomTat":"Vương Lâm chém kiếm thứ sáu mang oán khí ngập trời, dẫn động hàng loạt oan hồn tu sĩ bị thiên kiếp giết trong bảy trăm vạn thiên địa, thôn phệ toàn bộ máu thịt xương cốt đại trưởng lão Thiểm Lôi tộc chỉ còn nguyên thần. Đại trưởng lão trong tuyệt vọng cho nổ tộc ấn trên mi tâm nguyên thần, tu vi tăng vọt tạm thời, thân thể sấm sét tái tạo và giết sạch oan hồn, rồi phát động Tam Tức Thuật hút thọ nguyên Vương Lâm. Vương Lâm dùng Tuế nguyệt thuật nghịch chuyển ngàn năm đối kháng, đồng thời chém kiếm thứ bảy — trường kiếm bảy thước rời tay hóa cầu vồng phá nát tinh không, toàn bộ sinh linh bảy trăm vạn thiên địa hiến dâng tính mạng dung nhập vào kiếm, kiếm quang đâm xuyên nguyên thần đại trưởng lão. Đại trưởng lão gầm gọi sấm sét bất diệt cứu viện, thánh vật hóa thần lôi vạn trượng phá vỡ phong ấn gió bão khiến Tán Linh thượng nhân phun máu bị ép ra. Sấm sét bất diệt đối đầu trường kiếm, cả hai cùng tổn thương — trường kiếm tan vỡ, sấm sét bị trọng thương rút về miếu thờ thánh địa, mười sáu tu chân tinh anh Thiểm Lôi tộc mở đại trận phong tỏa. Tán Linh thượng nhân tuyên bố thiên địa đã tan vỡ, tiên giới đã mở, cuốn tất cả tộc nhân còn sống theo lỗ hổng hư vô thoát đi. Vương Lâm triệu Côn Cực Tiên phóng về phía nguyên thần đại trưởng lão đang sắp tử vong để kết liễu."},{"chuong":1273,"tieuDe":"Truyền Thuyết","tomTat":"Vương Lâm dùng Côn Cực Tiên thu nguyên thần đại trưởng lão Thiểm Lôi tộc (Thiên Nhân Đệ Ngũ Suy) đang sắp tiêu tán, đánh giá đây là cơ hội tạo hóa có thể dùng Tát Đậu Thành Binh và khai thác cảm ngộ sấm sét. Bảy trăm vạn thiên địa hoàn toàn sụp đổ sau đại chiến, Vương Lâm theo Tán Linh cùng tộc nhân thoát ra Thái Cổ Tinh Thần. Tán Linh kích động rơi nước mắt, tuyên bố tộc mình từ nay là tiên nhân, toàn tộc trăm vạn người ôm quyền thề đời đời kiếp kiếp trung thành với Vương Lâm, giao hơn một vạn Linh Niệm Lôi theo thỏa thuận. Vương Lâm quyết định tấn công Thiểm Lôi tộc để thôn phệ sấm sét bất diệt, hóa thân sấm sét phóng về đại trận phòng hộ, sấm sét tinh không tự ngưng tụ quanh hắn như đế vương xuất hành. Chương tiết lộ hai con đường trở thành Đệ Tam Bộ đại năng: phổ biến dựa hương hỏa môn đồ, và truyền thuyết cổ xưa tự lực bản nguyên đại thành không cần hương hỏa. Vương Lâm đang hướng về con đường truyền thuyết, tiến từng bước đến gần."},{"chuong":1274,"tieuDe":"Trụ Tinh Thần Sụp Đổ","tomTat":"Vương Lâm kéo lôi vực áp sát đại trận phòng hộ bao quanh mười sáu tu chân tinh Thiểm Lôi tộc, khiến Tán Linh thượng nhân đi sau vừa quan sát vừa kinh hãi trước sức mạnh của hắn. Khi đại trận hiện thành thanh quang và tử quang như vỏ trứng, các tu sĩ Thiểm Lôi tộc nhận ra bản thể Vương Lâm và liên hệ tới việc đại trưởng lão truy sát hắn chưa trở về, nhưng vẫn cố tin đại trưởng lão sẽ sớm quay lại. Vương Lâm thi triển Bát Long Hợp Nhất, Cửu Long Quy Vị, hợp tám hồn phách Thái Cổ Lôi Long với nguyên thần Thái Cổ Lôi Long của mình thành lôi long khổng lồ công phá trận pháp. Hắn công khai tuyên bố đại trưởng lão Thiểm Lôi tộc đã tan thân, nguyên thần bị bắt, còn sấm sét bất diệt cũng bị thương chạy về, nhưng tộc nhân Thiểm Lôi tộc vẫn cho rằng đó là lời làm loạn tâm thần. Lôi long liên tục va đập khiến đại trận tan rã và bị xé mở lỗ hổng lớn, để Vương Lâm và Tán Linh thượng nhân tiến vào trong. Mười một tu sĩ Thiên Nhân Suy Kiếp Thiểm Lôi tộc chia đội ngăn hai người, thậm chí có kẻ tự bạo tộc ấn để cố thủ. Trước niềm tin cố chấp ấy, Vương Lâm triệu Côn Cực Tiên, để thân roi bùng kim quang quấn tàn thần nguyên thần đã bị hủy hoại của đại trưởng lão Thiểm Lôi tộc, trực tiếp đánh sập trụ tinh thần của toàn tộc."},{"chuong":1275,"tieuDe":"Xuống Cho Ta","tomTat":"Vương Lâm đưa tàn thần Đại trưởng lão Thiểm Lôi Tộc bị Côn Cực Tiên quấn quanh ra trước mặt tộc nhân, khiến niềm tin của cả tộc sụp đổ. Nhân lúc đại loạn, hắn dùng huyết kiếm giết một tu sĩ Thiên Nhân Đệ Tứ Suy rồi giao thế cục rối loạn cho Tán Linh thượng nhân xử lý. Sau đó Vương Lâm cưỡi lôi long xông vào thánh địa Thiểm Lôi Tộc, phá tầng phòng hộ và làm miếu thờ chứa sấm sét bất diệt nổ tung. Sấm sét bất diệt suy yếu bỏ chạy lên hư vô, nơi một vòng xoáy khổng lồ mở ra để kéo nó vào trung tâm. Vương Lâm bám lấy sấm sét, bị lực lượng trong vòng xoáy kéo đến phun máu nhưng vẫn quyết tranh đoạt, rồi hóa thân Cổ Thần ngàn trượng để kéo nó xuống. Từ vòng xoáy vang ra âm thanh uy hiếp hắn buông tay, làm Thái Cổ Tinh Thần chấn động; tại Lam sơn trong Tam Ti tộc, Lý Thiến Mai có dấu hiệu ký ức thức tỉnh còn Lam Mộng Đạo Tôn biến sắc nhìn lên tinh không."},{"chuong":1276,"tieuDe":"Sứ Giả Thiên Đạo Xuất Hiện","tomTat":"Dấu hiệu Viễn Cổ Tiên Phi tái hiện, khiến Lam Mộng Đạo Tôn, các đại năng Đệ Tam Bộ trong Thái Cổ Tinh Thần và vài nữ tử ở Viễn Cổ Tiên Vực cùng biến sắc nhìn lên tinh không. Ở Man Hoang địa, Thác Sâm điên cuồng chống lại ý chí muốn biến hắn thành nô lệ, rồi cảm nhận khí tức đồng tộc quen thuộc liên quan tới Đồ Ti. Trong tinh không, Vương Lâm tiếp tục tranh đoạt sấm sét bất diệt bất chấp cảnh cáo từ vòng xoáy thần bí. Tồn tại trong vòng xoáy hiện cánh tay khổng lồ, gọi hắn là dư nghiệt Cổ Thần, nhưng Vương Lâm nhận ra đây là kẻ năm xưa cướp hồn phách Uyển Nhi. Hắn bùng nộ, hợp lực lượng Cổ Thần, hỏa lam sắc, lôi long, chiến ý và huyết kiếm thành một kiếm chém đứt bàn tay sứ giả thiên đạo. Vòng xoáy rút lui trong kinh nghi về thanh kiếm của hắn, còn Vương Lâm thề tương lai sẽ phá thiên địa để báo thù cho thê tử. Cuối cùng, hắn dùng Súc Địa Thành Thốn bắt kịp và nuốt sấm sét bất diệt, chuẩn bị luyện hóa nó cùng tám hồn phách Thái Cổ Lôi Long và minh ngộ sấm sét trong nguyên thần đại trưởng lão để khiến lôi bản nguyên đại thành."},{"chuong":1277,"tieuDe":"Thời Gian Yên Bình","tomTat":"Vương Lâm đi vào một đô thành phàm tục ở hướng tây, quan sát cách người nơi đây giao dịch bằng Phàn Tinh thay cho ngân lượng. Hắn dùng nguyên thần dò xuống lòng đất, tìm được mỏ Phàn Tinh rồi thu lấy một phần lớn cất vào không gian trữ vật. Sau đó hắn tới khu thành tây nghèo và đông đúc, mua một căn nhà, sống dưới thân phận học trò chờ kỳ thi năm sau. Đêm xuống, trong khung cảnh khói bếp, hàng xóm và tiếng gõ mõ cầm canh, lão chủ quán trước cổng đưa cho hắn một bình rượu gạo, khiến hắn cảm nhận được sự yên bình khác hẳn tu chân giới. Trong căn nhà đơn sơ, Vương Lâm âm thầm vận chuyển nguyên thần, dùng lôi bản nguyên, hỏa bản nguyên và hư ảnh Chu Tước để luyện hóa tám Thái Cổ Lôi Long bị giam giữ. Khi hắn uống rượu gạo, rượu hóa thành lực lượng hỏa diễm làm biển lửa bùng mạnh, giúp nguyên thần Thái Cổ Lôi Long của hắn lần lượt thôn phệ các lôi long bị luyện tan. Đến bình minh, hắn đã dung hợp bảy trong tám Thái Cổ Lôi Long, chỉ còn lại một con cuối cùng."},{"chuong":1278,"tieuDe":"Thái Cổ Tinh Thần Lệnh","tomTat":"Mưa lớn đổ xuống thành trì phàm nhân, khiến Vương Lâm nhớ lại tuổi thơ trên Chu Tước tinh và cảm khái quãng đường tu đạo hơn hai ngàn năm. Trên tầng mây, Nguyệt Huyên và thanh niên họ Dự gặp thanh niên họ Chu, từ đó biết Thiểm Lôi Tộc đã bị tiêu diệt, đại trưởng lão thất bại mất tích và Trường Tôn Hội đã ban Thái Cổ Tinh Thần Lệnh. Vân Lạc của Trường Tôn Hội dùng Thuật Thiên Đại Tinh Thần thôi diễn hình ảnh cùng ký ức thần thức của hung thủ, rồi phân tán cho sinh linh Thái Cổ Tinh Thần truy sát. Vương Lâm nghe được tin tức, hiểu rằng thời gian không còn nhiều nên lập tức luyện hóa con Thái Cổ Lôi Long cuối cùng. Sau nửa ngày, đủ tám Thái Cổ Lôi Long dung nhập nguyên thần, khiến lôi bản nguyên trong người hắn tăng mạnh và nguyên thần hóa thành tia chớp nối liền thiên địa trong cơ thể. Sấm mưa dị thường bao phủ tu chân tinh làm các tu sĩ ở hoàng thành phía đông và lão nhân Chân Ngôn Tộc bất an nhưng chưa phát hiện manh mối. Cuối chương, Vương Lâm thả sấm sét bất diệt của Thiểm Lôi Tộc ra, dùng nguyên thần lôi đình thôn phệ và thi triển Đạo thuật Dung hợp để hướng tới lôi bản nguyên đại thành."},{"chuong":1279,"tieuDe":"Ba Hình Ảnh","tomTat":"Trong đêm mưa bão, thành trì trở nên vắng lặng, còn tại thành tây, một lão già mặc đạo bào dẫn bảy tu sĩ trung niên thi triển thuật tộc ấn để truy tìm tu sĩ che giấu. Hào quang từ tộc ấn khiến nhà cửa, phàm nhân và dấu vết người chết hiện ra như bị nghịch chuyển năm tháng, nhưng khi quét tới căn nhà lụp xụp của Vương Lâm thì bị hắn vung tay phá hình ảnh dò xét. Lão già không phát hiện được Vương Lâm, kết luận nơi này không có tu sĩ ẩn náu rồi rời đi, trong khi cuộc lùng sục tương tự đang lan khắp các tu chân tinh, tinh cầu bỏ hoang và tinh không theo mệnh lệnh của Thái Cổ Tinh Thần. Bên trong nguyên thần, Vương Lâm tiếp tục thôn phệ sấm sét bất diệt, luyện hóa hoàn toàn ý chí trong đó và khiến lôi bản nguyên tăng vọt, riêng tu lôi đạt tới Toái Niết hậu kỳ. Sau khi luyện hóa, hắn nhìn thấy ba hình ảnh ký ức: một kiếp nạn tan vỡ vượt xa Nội giới và Ngoại giới, một người đàn ông trung niên có đồ án hoa bảy cánh từng đưa sấm sét bất diệt vào hư vô, và miếu thờ Thiểm Lôi Tộc nơi có tám tu sĩ cùng một thủ lĩnh có kim quang. Khoảnh khắc thủ lĩnh ấy xoay người, Vương Lâm chấn động như nhận ra thân phận của đối phương."},{"chuong":1280,"tieuDe":"Cực Cảnh Năm Màu","tomTat":"Sau khi hình ảnh tiêu tán, Vương Lâm ghi nhớ nam tu sĩ lạ có ánh sáng năm màu trong mắt trái và nhận ra đó là Cực Cảnh, liên hệ ngay với Nạp Đa, Côn Cực Tiên, Chu Tước tinh và khả năng đám tu sĩ thần bí từng vào Nội giới. Hắn kiểm nghiệm trạng thái bản thân, phát hiện khi dùng lực lượng sấm sét thì tu vi vượt Toái Niết trung kỳ lên Toái Niết hậu kỳ, nhưng khi chỉ dùng hỏa, ý cảnh và nguyên lực thiên địa thì vẫn ở Toái Niết trung kỳ. Giữa đêm mưa, hắn mặc áo tơi rách rời phòng, đi qua thành tây vào tửu lâu mua một bầu rượu rồi tiếp tục hướng thành bắc. Cùng lúc, lão già đạo bào và bảy người đàn ông trung niên của Thái Cổ Tinh Thần đang lục soát tinh vực để tìm hung thủ hủy diệt Thiểm Lôi tộc, đồng thời nhắc Vân Lạc Đại Tư Trường Tôn Hội đã tính ra mục tiêu ở trong khu vực này. Vương Lâm âm thầm áp sát trong sấm chớp, cắt một phần nguyên thần của lão già đạo bào mà đối phương và nhóm đi theo gần như không phát giác. Trở về phòng, hắn bóp nát phần nguyên thần để đọc ký ức, biết rõ vòng truy tìm diện rộng và mối nguy từ thần thông suy tính của Vân Lạc. Cuối chương, hắn lấy nguyên thần đại trưởng lão Thiểm Lôi tộc ra nuốt vào, khiến nguyên thần sấm sét biến hóa thành hình dạng đại trưởng lão và gọi sáu loại lôi gồm Thiên Ẩn Lôi, Địa Dung Lôi, Nguyên Hóa Lôi, Từ Hợp Lôi, Đạo Ý Lôi, Linh Niệm Lôi xuất hiện."},{"chuong":1281,"tieuDe":"Tư Mặc Tử","tomTat":"Vương Lâm truyền Lôi Lục đạo từ thần niệm nguyên thần, khiến hào quang và lôi quang bùng phát ngoài dự tính, suýt làm lộ tung tích trên tu chân tinh. Nhận ra sơ hở, hắn lập tức rời căn nhà tới sơn cốc sâu trong Thập Vạn đại sơn để luyện hóa, trong khi nhiều nhóm tu sĩ trên tinh cầu cảm nhận dị biến và bắt đầu truy dấu. Ở vùng sâu Thái Cổ tinh thần, Vân Lạc dùng quả cầu nước suy tính ra hình bóng cùng vị trí của Vương Lâm rồi báo cho Trường Tôn Hội và các trưởng lão. Trường Tôn Hội phát lệnh tụ tập tu sĩ trong phạm vi rộng quanh tu chân tinh mục tiêu, đồng thời gửi huyết chỉ treo thưởng đạo linh cho Tư Mặc Tử. Tư Mặc Tử, một đại năng Đệ Tam Bộ từng đuổi giết Thác Sâm, đang hấp thu Lục Phẩm đạo linh trong khe nứt hư vô và phóng ra hư ảnh Thiên Nhân Đệ Ngũ Suy để nhận nhiệm vụ truy bắt. Giữa cuộc lục soát, Vương Lâm hấp thu toàn bộ Linh Niệm lôi Thiểm Lôi tộc tích lũy, khiến nguyên thần sấm sét và lôi tu tăng mạnh nhưng vẫn kiên quyết không chọn con đường hương hỏa. Sau một ngày, vài vạn tu sĩ gần như lật tung tu chân tinh của Chân Ngôn Tộc, kể cả Thập Vạn đại sơn, nhưng vẫn không tìm được dấu vết Vương Lâm."},{"chuong":1282,"tieuDe":"Cánh Cửa Không Chi","tomTat":"Vương Lâm ẩn trong Thập Vạn Đại Sơn, hòa khí tức vào hoàn cảnh nên các tu sĩ và thần thức truy tìm đều không phát hiện được. Hắn lần lượt luyện hóa Thiên Ẩn lôi, thôn phệ Địa Dung lôi, áp chế Nguyên Hóa lôi rồi cưỡng ép hấp thu Từ Hợp lôi, nhờ đó phá Toái Niết hậu kỳ và tiến vào Toái Niết đại viên mãn. Đạo Ý lôi chứa đạo niệm tu sĩ Nội giới tự chủ động dung hợp với nguyên thần hắn, khiến lôi tu đạt Toái Niết đỉnh phong trong Đệ Nhị Bộ. Không tìm được ba luồng lôi cuối, Vương Lâm tự định Cực cảnh là luồng sấm sét thứ bảy, phong Lôi Oa thành Huyết Mạch lôi thứ tám, rồi lấy cả đời nghịch tu tạo Nghịch mệnh lôi thứ chín. Chín luồng sấm sét hoàn chỉnh khiến lôi đình phủ kín thiên địa, làm các tu sĩ Thái Cổ Tinh Thần đang truy tìm chuyển từ hưng phấn sang hoảng sợ. Khi Nghịch mệnh lôi nhập vào mắt phải, Không Đại Môn của Đệ Tam Bộ hiện ra bao phủ bầu trời, và Vương Lâm quyết định dù không chắc phá được vẫn phải thử một lần."},{"chuong":1283,"tieuDe":"Sấm Sét Vang Trời","tomTat":"Vương Lâm xé cấm chế ẩn thân, hiện thân giữa thiên địa và vận dụng lôi bản nguyên đại thành để gọi lôi đồ từ mắt phải lao ra. Hắn dẫn động sấm sét trong tinh không, khiến lôi đồ phóng lớn rồi va vào cánh cửa Không Chi nhằm phá vách ngăn tiến lên Đệ Tam Bộ. Lần công kích khiến cánh cửa xuất hiện một khe nứt nhỏ, nhưng lực phản chấn cũng làm Vương Lâm trọng thương và rơi xuống mặt đất. Không dây dưa với vài vạn tu sĩ xung quanh, hắn dẫn sấm sét dung nhập Thập Vạn Đại Sơn, hóa thành mười vạn lôi sơn trấn áp họ và dùng lôi đồ gia cố thế áp chế. Sau đó Vương Lâm dùng Súc địa Thành Thốn rời khỏi chiến trường, nhận định cuộc truy sát của Thái Cổ Tinh Thần mới chỉ bắt đầu. Trong tinh không, hắn hiểu rằng một luồng bản nguyên đại thành chưa đủ phá Không Môn, nên quyết tâm khiến nhiều bản nguyên đại thành để đánh vỡ vách ngăn Đệ Tam Bộ."},{"chuong":1284,"tieuDe":"Nhận Lầm Người","tomTat":"Sau khi Vương Lâm rời tu chân tinh Chân Ngôn Tộc, Tư Mặc Tử phân thân đến Thập Vạn Đại Sơn và quan sát dấu vết Không Môn cùng vài vạn tu sĩ còn bị lôi lực trấn áp. Hắn dùng pháp thuật tái hiện cảnh Vương Lâm ba lần đánh Không Môn, từ đó kinh hãi nhận ra Vương Lâm không dựa vào hương hỏa mà chỉ dùng bản nguyên đại thành vẫn khiến Không Môn xuất hiện và nứt ra. Tại Lam Sơn, Lam Mộng Đạo Tôn cũng hiện ảnh sự việc, thừa nhận đã xem thường Vương Lâm, còn Lý Thiến Mai cho biết ký ức của nàng đã khôi phục một phần và khi nhớ lại hoàn toàn sẽ đi tìm hắn. Trong tinh vực Phiêu Miễu tộc, cô gái hắc y chứng kiến hoa cỏ héo rũ, hồ nước cuộn xoáy và sấm sét giáng xuống, rồi nhận ra chín quẻ tổ tiên truyền lại đã ứng ba quẻ. Chương sau đó giới thiệu Điên Lạc Địa, vùng hỗn loạn do ba trăm bảy mươi hai bộ tộc nhỏ tạo thành, từng khiến cả đại tộc, Cửu Thiên Ma Tôn và Trường Tôn Hội phải kiêng kỵ. Vương Lâm dựa vào ký ức truyền thừa để vào nơi này, dùng đan dược đổi động phủ trăm năm và bế quan chữa thương, nhưng cuối chương cửa động phủ mở ra và một người nhanh chóng bước vào."},{"chuong":1285,"tieuDe":"Ta Không Thể Nhịn!","tomTat":"Chung Đại Hồng dò hỏi tình hình trên tu chân tinh rồi báo với Vương Lâm rằng nơi này đan dược cực kỳ quý giá, con rối cũng có thể mua bán, còn tin tức về Thái Cổ Tinh Thần Lệnh vẫn chưa lan tới. Được Vương Lâm giao đan dược, hắn dùng hồn đan kết giao lão họ Chương và nhờ lão dẫn tới thành trì hoang phế do Ám Hạt Tộc nắm giữ để mua một con rối Hóa Thần sơ kỳ. Sau khi giao dịch hoàn tất, thiếu chủ Ám Hạt Tộc sinh lòng truy xét nguồn gốc hồn đan, sai người bắt lão họ Chương, đánh trọng thương Chung Đại Hồng và lưu lại lạc ấn thần thức để lần theo nơi hắn trở về. Chung Đại Hồng mang con rối về động phủ, tự trách vì đã gây họa và cho rằng có thể nhẫn nhịn để tránh làm lộ hành tung của Vương Lâm. Nhưng Vương Lâm nhìn ra thương thế độc ác cùng dấu vết truy tung trên người hắn, khẳng định Chung Đại Hồng đã là người của mình nên chuyện này không thể bỏ qua. Vương Lâm lập tức bắt Chung dẫn đường trở lại thành trì Ám Hạt Tộc, cho tu sĩ trong thành ba hơi thở rời đi rồi dẫn lôi đình từ bốn phương tám hướng đánh xuống. Cả thành trì, đại điện và bảo tháp ẩn dưới đất bị phá tan, khiến lão họ Chương cùng nam tử trung niên Ám Hạt Tộc kinh hãi nhận ra người đứng trước mặt chính là chủ nhân của Chung Đại Hồng."},{"chuong":1286,"tieuDe":"Viêm Hỏa Dị Tinh","tomTat":"Sau khi Chung Đại Hồng nhận ra nam tử trung niên Ám Hạt Tộc là kẻ liên quan đến việc hại người của mình, Vương Lâm lập tức ra tay, dùng một chỉ dẫn lôi đình đánh cho đối phương thân diệt thần vong trước sự kinh hãi của đám tu sĩ quanh thành. Hắn không dừng lại ở đó mà phá bảo tháp của Ám Hạt Tộc, tiến xuống từng tầng, lần lượt phong ấn thiếu chủ dùng Ám hạt châu đánh lén cùng nhiều tộc nhân khác bằng lôi điện và biển lửa. Từ tầng sâu nhất, lão giả Ám Hạt Tộc có tu vi thiên nhân đệ nhị suy xuất hiện, thi triển tộc ấn bọ cạp và con rối để chống trả, còn viện danh Điên Lạc đại đế uy hiếp, nhưng vẫn bị Vương Lâm dùng lực Cổ Thần cùng khí thế một chỉ trấn áp đến mức nguyên thần xuất khiếu. Vương Lâm buộc toàn bộ Ám Hạt Tộc quy phục, và theo lời nhắc của Chung Đại Hồng, lão giả phải lấy tộc ấn phát lời thề thái cổ, khiến một trăm bảy mươi sáu tộc nhân trở thành thế lực đầu tiên của hắn tại Điên Lạc. Sau khi quy phục, lão giả trình bày cục diện Điên Lạc: nơi này có ba trăm bảy mươi hai tiểu tộc, Lạc Sinh hội mười ba trưởng lão, Điên Lạc đại đế là cường giả bước thứ ba, còn hệ thống con rối cao cấp được giao dịch trong phạm vi các bộ tộc trưởng lão. Vương Lâm tiếp tục hỏi về Hỏa Tước tộc và biết Hải hồn tông được phái tới Điên Lạc để giao dịch con rối, kết giao các tộc và âm thầm sưu tầm Viêm hỏa dị tinh. Khi lão giả dâng ra một mảnh Viêm hỏa dị tinh, Vương Lâm nhận ra vật này liên hệ với lời Chu Tước lão Thánh Hoàng từng nói rằng Tứ Thánh Tông vốn xuất thân từ Thái Cổ Tinh Thần, đồng thời sinh nghi về lai lịch của Điên Lạc đại đế."},{"chuong":1287,"tieuDe":"Tư Mặc Tử Tới Rồi","tomTat":"Kiệt trưởng lão lấy ra Viêm hỏa dị tinh, khiến Vương Lâm lập tức nhận ra vật này giống hòn đá trắng nơi Chu Tước lão Thánh Hoàng từng tọa trong Chu Tước Thánh Tông. Từ ký ức về Lỗ Vân và các đời Thánh Hoàng, Vương Lâm suy đoán Điên Lạc có thể liên quan tới Chu Tước Thánh Tông, thậm chí có dấu vết Chu Tước Thánh Hoàng đời thứ tư, mở ra khả năng giúp Chu Tước của hắn thức tỉnh lần thứ tư. Hắn thu Viêm hỏa dị tinh rồi chuyển sang nghiên cứu con rối nam tử trung niên của Ám Hạt Tộc, phát hiện thân thể nó không có huyết nhục mà do tinh thể kỳ dị cấu thành, bên trong còn kinh mạch khô héo. Vương Lâm triển khai lôi đồ để tăng tu vi và thần thức, công phá tầng phòng hộ trong con rối rồi dùng Định thân thuật trong khoảnh khắc cuối để thấy nguyên thần giống hệt con rối, xác nhận nó vốn là tu sĩ bị tế luyện. Khi con rối nổ tung, hắn liên hệ tinh thể trong thân nó với tinh thể ở vết thương đầu lâu Cổ Thần từng gặp tại vùng đất Yêu Linh, khiến nghi vấn về Điên Lạc đại đế càng sâu. Sau đó Vương Lâm rời động phủ, lệnh Kiệt trưởng lão dẫn tới tu chân tinh của trưởng lão Lạc Sinh hội gần nhất. Cùng lúc, Tư Mặc Tử xuất hiện ngoài Điên Lạc, biết nhờ Vân Lạc đại ti tính ra tung tích Vương Lâm và dự định mượn quan hệ với tộc trưởng Long Giáp Tộc để truy tìm, sưu hồn Vương Lâm lấy bí mật dẫn động hương hỏa."},{"chuong":1288,"tieuDe":"Sơ Ngộ Hỏa Tước","tomTat":"Tộc trưởng Ám Hạt Tộc dẫn Vương Lâm rời tu chân tinh Ám Hạt Tộc tới chủ tinh Long Giáp Tộc, giải thích nơi này có phường thị bán con rối và Viêm hỏa dị tinh, nhưng dị tinh thường bị Hỏa Tước tộc tranh mua giá cao. Trên đường vào chủ tinh, ba tu sĩ Long Giáp Tộc ra đón và chú ý việc tộc trưởng Ám Hạt Tộc kính cẩn để Vương Lâm đi trước. Vương Lâm phát hiện Tư Mặc Tử trong tinh không, nhận ra đây là một trong ba tu sĩ bước thứ ba từng truy đuổi Thác Sâm và đoán đối phương bám tới để giết mình. Tư Mặc Tử cũng xác nhận Vương Lâm nhờ hình dáng, khí tức do Vân Lạc tính ra, nhưng chưa ra tay vì kiêng kỵ Điên Lạc đại đế, rồi được trưởng lão thứ chín Lạc Sinh hội họ Tôn ra nghênh đón. Vương Lâm vì vậy đổi kế hoạch, không chỉ mua vật mà chuẩn bị ở Long Giáp Tộc đánh một trận với Tư Mặc Tử nếu có cơ hội. Sau đó hắn tới lầu các cửa hàng Long Giáp Tộc ở phường thị phía đông, khiến nữ tử quản sự kinh ngạc khi thấy tộc trưởng Ám Hạt Tộc đứng sau hắn không dám ngồi. Khi Vương Lâm vừa nêu yêu cầu mua Viêm hỏa dị tinh, một lão giả áo đỏ Hỏa Tước tộc mang khí tức biển lửa bước lên lầu hai, tuyên bố cũng muốn mua dị tinh và yêu cầu hắn nhường."},{"chuong":1289,"tieuDe":"Có Dám Đánh Một Trận!","tomTat":"Trong lầu giao dịch của Long Giáp Tộc, lão giả Hỏa Tước tộc định tranh Viêm hỏa dị tinh nhưng lập tức bị Vương Lâm dùng một tiếng hừ và ánh mắt trấn áp đến phun máu, buộc phải hạ mình xưng vãn bối. Vương Lâm dùng hồn đan chế từ hỏa thú đỉnh cấp đổi ba khối Viêm hỏa dị tinh, cố ý để lộ khí tức hỏa bổn nguyên trong đan khiến lão giả Hỏa Tước tộc động tâm, đồng thời giao dịch với thiếu tộc trưởng Long Giáp Tộc để lấy một vạn Băng long đan. Sau khi rời lầu, hắn cho tộc trưởng Ám Hạt Tộc trở về trước, còn mình tiếp tục thả mồi để Hỏa Tước tộc chủ động tìm đến; quả nhiên lão giả âm thầm theo sau và đổi một trăm Viêm Hỏa dị tinh lấy một trăm hồn đan. Trên đỉnh núi, Vương Lâm dùng đạo thuật Dung, hỏa diễm, lôi đình, máu Cổ Thần và tinh khí nguyên thần luyện một vạn Băng long đan thành một viên đan sát thương đủ uy hiếp cường giả thiên nhân đệ ngũ suy. Hắn lại luyện toàn bộ Viêm hỏa dị tinh thành tinh thể hỏa hệ lam đậm có hình ảnh Chu Tước, rồi dùng bổn nguyên lôi đình phá một phần phong ấn cuối của đoạn kiếm lộc cốt, khiến kiếm khí tăng vọt tới gần bốn ngàn vạn đạo. Cùng lúc, Hỏa Tước tộc luyện hồn đan phát hiện một giọt máu bí ẩn là nguồn khí tức bổn nguyên, còn Long Giáp Tộc lại đổi trắng thay đen, vu cho Vương Lâm cướp một vạn Băng long đan để nhờ Tư Mặc Tử ra tay. Sau khi chuẩn bị xong sát chiêu và pháp bảo, Vương Lâm đứng trên đỉnh núi truyền tiếng khắp tu chân tinh, công khai khiêu chiến Tư Mặc Tử và chờ đối phương đến đánh một trận."},{"chuong":1290,"tieuDe":"Đại Tông Sư","tomTat":"Tư Mặc Tử phát hiện Vương Lâm đang đứng chờ trên đỉnh núi của tu chân tinh, lập tức rời đại điện Long Giáp Tộc để nghênh chiến. Ở lại phía sau, tộc trưởng Long Giáp Tộc nhận ra Vương Lâm chính là kẻ từng hủy Thiểm Lôi tộc và bị Trường Tôn hội truy nã, nhưng vẫn đặt cược vào Tư Mặc Tử cùng thân phận trưởng lão Lạc Sinh hội của mình. Chương đồng thời khắc họa Vương Lâm sau hai ngàn năm tu đạo đã có khí độ đại tông sư, đủ tư cách đối đầu phân thân tu sĩ bước thứ ba dù tu vi chưa thật sự bước vào cảnh giới ấy. Trong tinh không, Tham Lang đang bỏ chạy thì bị huyết quang kinh thiên đánh trọng thương, để lộ áo giáp ẩn giấu và mất khả năng khống chế phiến lá phong ấn, nhờ đó Vương Lâm thoát ra rồi đoạt lấy phiến lá. Trở lại chiến trường, Vương Lâm đối kháng cơn lốc thần thông của Tư Mặc Tử bằng Sơn Băng thuật, hút toàn bộ sơn hồn trên tu chân tinh để khiến thần thông này đạt viên mãn và bộc phát đệ cửu băng. Tư Mặc Tử nhận ra đây là thần thông của Bạch Phàm, sau đó thi triển thuật biến trời thành tranh, đất thành mực, bản thân thành bút, khiến Vương Lâm liên tưởng tới Phá Thiên Đạo của Phá Thiên tông. Từ mối liên hệ với Tư Mã Mặc và quy tắc chỉ tông chủ hoặc đại đệ tử Phá Thiên tông mới được tu hành thuật này, Vương Lâm bắt đầu nghi ngờ thân phận thật sự của Tư Mặc Tử."},{"chuong":1291,"tieuDe":"Đại Đế!","tomTat":"Tư Mặc Tử dùng Phá Thiên Đạo, lấy bức tranh thiên địa và mặt đất hóa mực để vẽ ra tu chân tinh cùng thân ảnh Vương Lâm, chuẩn bị khép thần thông giết hắn. Vương Lâm hét lên Phá Thiên tông và Tư Mã Mặc, khiến Tư Mặc Tử khựng lại, rồi lập tức áp sát tung một chỉ chứa gần bốn ngàn vạn đạo kiếm khí, phá phòng ngự và trọng thương phân thân đối phương. Tư Mặc Tử vẫn phát động Phá Thiên Đạo, làm thiên địa trong tranh rạn vỡ và khiến các tu sĩ quan chiến như lão giả Hỏa Tước tộc, Thiếu tộc trưởng và Tộc trưởng Long Giáp Tộc đều tưởng Vương Lâm tất chết. Nhưng Vương Lâm dùng kiếm khí bao quanh thân, tự hóa thành kiếm khí phá sập thiên địa thần thông và lao ra ngoài. Hắn tuyên bố trận chiến mới bắt đầu, thi triển Phiên thiên thần thông nghịch chuyển trời đất để nén Tư Mặc Tử, còn Tư Mặc Tử dùng đại phiên mười trượng phóng Tuế Nguyệt Cấm chống lại. Đúng lúc hai bên giằng co, tiếng nói của Đại đế vang từ hư vô, hứa bảo đảm Vương Lâm bình an ở Điên Lạc Địa nếu hắn thắng phân thân bước thứ ba trong năm nhịp thở, rồi bắt đầu đếm."},{"chuong":1292,"tieuDe":"Bốn Nhịp Thở!","tomTat":"Trận chiến giữa Vương Lâm và Tư Mặc Tử bị đặt trong giới hạn năm nhịp thở, khiến tộc trưởng Long Giáp Tộc, lão giả Hỏa Tước tộc và cả Tư Mặc Tử đều cho rằng Vương Lâm không thể kết thúc nhanh như vậy. Tư Mặc Tử thi triển Thiên hoang địa lão ngộ từ Tuế Nguyệt cấm, làm thiên địa suy hoại rồi dùng chưởng ấn chứa lực thiên nhân đệ ngũ suy ép tới. Vương Lâm ngưng tụ Quang ảnh thuẫn, liên tục dựng thuẫn ba lần trong một hơi thở để chiết xạ phần lớn lực công kích. Sang nhịp thứ hai và thứ ba, hắn triển khai lôi bổn nguyên, chín đạo ấn ký lôi đình và lôi đồ vạn trượng, hòa thân vào lôi đồ để phá tan Tuế Nguyệt cấm, đánh Tư Mặc Tử thổ huyết trọng thương. Dù bị lực Tuế Nguyệt quét qua làm già nua, Vương Lâm dùng sinh cơ trong cơ thể nghịch chuyển và nhanh chóng khôi phục. Trước khi tiếng bốn kết thúc, hắn truy kích bằng viên đan dược màu vàng rồi kích nổ ở cự ly gần, làm phân thân Tư Mặc Tử rách thịt gãy xương, đồng thời hé lộ phân thân này là vật do bổn tôn bước thứ ba luyện hóa khi tu vi đình trệ ở Không Niết sơ kỳ. Ngay sau đó, Vương Lâm tiếp tục đưa Viêm hỏa dị tinh bị áp súc tới gần và cho nổ, tạo đợt hủy diệt thứ hai khiến tộc trưởng Long Giáp Tộc đang quan sát bằng thần thức biến sắc dữ dội."},{"chuong":1293,"tieuDe":"Thiếu Đế","tomTat":"Sau dư âm vụ nổ đan dược, Tư Mặc Tử đã trọng thương nhưng vẫn chưa chết, Vương Lâm tiếp tục kích nổ Viêm hỏa dị tinh rồi dùng huyết kiếm xuyên ngực đối thủ. Khi Tư Mặc Tử định thuấn di bỏ chạy khỏi vùng đất Điên Lạc, một giọng nói từ hư vô vang lên và một ngón tay khổng lồ từ dòng xoáy trên trời điểm xuống chặn hắn. Vương Lâm nhận ra vị đại đế trong vùng này đang giúp mình, tạm gác bí ẩn về pho tượng và chuyển sang kiểm tra pháp bảo lấy từ Tham Lang. Hắn xác nhận chín mươi chín thanh phi kiếm là bảo vật Cổ Yêu chứa yêu khí nồng đậm, giữ lại cho phân thân Cổ Yêu, rồi lấy Hộ Cốt Thạch Bi ra và thấy chín tấm bia đá tỏa khí tức Cổ Thần. Sau đó Vương Lâm tới Long Giáp Tộc để tính sổ vì tộc trưởng từng giúp Tư Mặc Tử, một chưởng đánh tan gần mười tu sĩ bước thứ hai và khiến lãnh địa trong tộc sụp đổ. Tộc trưởng Long Giáp Tộc dùng thân phận trưởng lão thứ chín Lạc Sinh hội để uy hiếp, nhưng sứ giả của đại đế xuất hiện, tước tư cách trưởng lão và ban Độc mệnh đan cho hắn. Cuối cùng, sứ giả đổi thái độ cung kính với Vương Lâm, ôm quyền xưng thuộc hạ và tham kiến hắn là thiếu đế."},{"chuong":1294,"tieuDe":"Cố Nhân","tomTat":"Sứ giả của Điên Lạc đại đế đến Long Giáp Tộc, tuyên bố Vương Lâm là thiếu đế do đại đế lựa chọn, địa vị cao hơn mười ba trưởng lão, khiến toàn tộc kinh hãi vì trước đó đã đắc tội hắn. Tộc trưởng Long Giáp Tộc cầu xin tha cho nhi tử độc nhất rồi tự tay phế sạch kinh mạch, nguyên thần và tu vi của Thiếu tộc trưởng, nhờ vậy được Vương Lâm gật đầu tha mạng cho con. Sau đó tộc trưởng nuốt độc đan do sứ giả mang tới, đan dược hóa hắc hỏa thiêu rụi nguyên thần và thân thể hắn, khiến Vương Lâm nhận ra đây cũng là lời cảnh cáo gián tiếp của đại đế. Theo yêu cầu của sứ giả, Vương Lâm chọn một thanh niên Khuy Niết làm tân tộc trưởng Long Giáp Tộc; người này lập tức thần phục và nhận lệnh giao toàn bộ Băng long đan, Viêm hỏa dị tinh cùng con rối cho Vương Lâm. Sứ giả tiếp tục trao ngọc bội xanh chữ “đế” làm tín vật thân phận thiếu đế và truyền lời mời Vương Lâm dự tuyển chọn trưởng lão Lạc Sinh hội sau ba tháng. Ngoài tinh vực Điên Lạc, bổn tôn Tư Mặc Tử cảm ứng phân thân đã chết, nổi giận vì kế hoạch tế luyện thân thể bước thứ ba bị phá, đồng thời nghi Vương Lâm đến từ giới nội. Hắn triệu ra hai mươi chín cây Thất Thải Thần Không Đinh do Chưởng tôn ban và tính chờ Trường Tôn hội quyết định để hợp lực đối phó Điên Lạc đại đế. Cuối chương, Tham Lang được gần một ngàn tu sĩ hộ tống trong Điên Lạc tinh vực, hướng tới tu chân tinh Ám Hạt Tộc để tìm thi thể bọ cạp vạn cổ vì nơi đó được cho là khả năng cao nhất có bảo vật."},{"chuong":1295,"tieuDe":"Tham Lang","tomTat":"Chương mở ra bằng danh tiếng của Tham Lang tại vùng đất Điên Lạc: lai lịch thần bí, tu vi ban đầu không quá cao nhưng sở hữu nhiều đan dược, pháp bảo và các thần thông quỷ dị, đặc biệt là khả năng bỏ chạy cực nhanh. Trong các lần bị truy sát, hắn liên tục lấy ra pháp bảo chưa từng lộ, khiến ba tu sĩ Toái Niết bị thương, một người bị giết, rồi dùng pho tượng tàn phá diệt tu sĩ thiên nhân đệ nhất suy, làm danh tiếng chấn động. Sau một thời gian biến mất, hắn được đồn là được Điên Lạc đại đế coi trọng, dâng pháp bảo để nhận đan dược, nhờ đó tu vi tăng tới Toái Niết trung kỳ và khiến cả tu sĩ thiên nhân đệ tứ suy tham bảo cũng trọng thương rời đi. Chương cũng hé lộ thiên phú tìm bảo của Tham Lang cùng nghịch lân là mùi thối trên thân thể, thứ đã ăn sâu vào nguyên thần và khiến hắn căm ghét bất cứ ai nhắc tới. Hiện tại, Tham Lang dẫn hơn mười tu sĩ tới gần tu chân tinh Ám Hạt Tộc, nhắm tới bảo vật của Vân Độn Tộc có thể tiêu trừ mùi thối. Trên đường đi, hắn hồi tưởng các tai họa từ Thiên Vận Tử, Vọng Nguyệt đến Vương Lâm, đặc biệt xem Vương Lâm là khắc tinh từng đoạt nhiều pháp bảo của mình. Nỗi sợ Vương Lâm trở thành khe hở trong đạo tâm Tham Lang, và chương khép lại bằng nhận định hắn chỉ có thể phá ác mộng này nếu tự tay giết được Vương Lâm."},{"chuong":1296,"tieuDe":"Chim Sợ Cành Cong","tomTat":"Vương Lâm rời tu chân tinh Long Giáp Tộc, mang theo toàn bộ tích lũy của tộc này gồm Băng long đan, Viêm hỏa dị tinh và nhiều con rối, đồng thời suy xét việc Điên Lạc đại đế giết phân thân Tư Mặc Tử, ban danh hiệu thiếu đế và hẹn hắn ba tháng sau tới Lạc Sinh hội. Hắn nghi đại đế có thể nhìn ra năm đạo bổn nguyên lực hoặc thân phận Chu Tước của mình, nhưng vẫn chỉ xem đó là phỏng đoán và quyết định sẽ tới Lạc Sinh hội để tìm hiểu. Trong lúc hắn dùng súc địa thành thốn quay về, Tham Lang đã dẫn hơn một ngàn tu sĩ Vân Độn tộc tới tu chân tinh Ám Hạt Tộc, tuyên bố chiếm dụng nơi này ba tháng để tìm vật và ép toàn tộc rời đi. Chung Đại Hồng đang răn dạy Ám Hạt Tộc thì vì nôn trước mùi thối của Tham Lang mà chọc giận đối phương, khiến Tham Lang dùng quạt lớn phá núi, phá động phủ Vương Lâm và đánh thương nhiều người. Bị bắt tới trước mặt Tham Lang, Chung Đại Hồng vội lấy uy danh Vương Lâm ra dọa để giữ mạng. Tham Lang không giết hắn ngay mà phô bày chín bia đá, chín mươi chín kiếm, thanh quang hóa rừng, thụ nhân, Thiên Hoàng lô và trường thương sương mù để chứng minh kho pháp bảo của mình trước Vân Độn tộc. Khi Vương Lâm xuất hiện từ gợn sóng trên bầu trời, Tham Lang nhận ra khắc tinh từng cướp sạch pháp bảo của mình, lập tức hoảng sợ bỏ chạy ngay cả pháp bảo đã xuất ra cũng không kịp thu hồi, khiến tất cả sững sờ."},{"chuong":1297,"tieuDe":"Thu Bảo","tomTat":"Vương Lâm bất ngờ gặp lại Tham Lang ở Thái Cổ Tinh Thần, dù trong ký ức hắn Tham Lang đã chết ở Vọng Nguyệt. Tham Lang vừa thấy Vương Lâm đã lập tức bỏ chạy, để lại hơn ngàn tu sĩ và hàng loạt pháp bảo trên tu chân tinh Ám Hạt Tộc. Vương Lâm bình tĩnh dùng đại thủ và nguyên thần tinh khí thu chín mươi chín phi kiếm, xóa thần thức ấn ký của Tham Lang, rồi lần lượt đoạt Hộ Cốt Cửu Bi, Vụ Ma Thương và Thiên Hoàng Lô. Tham Lang ở xa nhiều lần cảm ứng pháp bảo bị đoạt, từ ý định quay lại trả thù chuyển thành hoảng sợ, coi Vương Lâm là sát tinh và tiếp tục chạy sâu vào vùng đất Điên Lạc. Trong lúc kiểm tra chiến lợi phẩm, Vương Lâm nhận ra Vụ Ma Thương có khí tức Cổ Ma, Thiên Hoàng Lô liên quan Cổ Yêu, còn thụ nhân Táng Thiên Mộc Linh có phòng hộ cực mạnh nên cũng thu vào không gian trữ vật. Sau cùng, hắn lấy Đế lệnh ra khiến một lão giả nhận ra uy quyền của lệnh vật, ra lệnh hơn ngàn tu sĩ ở lại nghe Chung Đại Hồng rồi rời khỏi tu chân tinh."},{"chuong":1298,"tieuDe":"Đầu Mối","tomTat":"Trong tinh không vùng đất Điên Lạc, Tham Lang bị Vương Lâm bám sát nên liên tiếp dùng phiến lá khô thi triển Nhất diệp phong thiên, phong bế gợn sóng không gian nơi Vương Lâm sắp hiện thân. Vương Lâm thử phá phong ấn nhưng bị phản chấn, lập tức đổi cách vòng qua để tiếp tục truy kích. Tham Lang nhờ thuật bỏ chạy và hai ma ảnh màu tím nhiều lần đoán trước đường truy đuổi, nhưng bất ngờ bị Huyết kiếm xuyên qua, áo giáp ẩn thân nứt vỡ và phiến lá khô bị Vương Lâm đoạt, phong ấn, cất vào không gian trữ vật. Vương Lâm càng thêm xác định Tham Lang là nguồn vận may và là đầu mối liên quan đến cách tiến vào Thái Cổ Tinh Thần. Bị ép đến đường cùng, Tham Lang dùng bình ngọc màu đen khắc Cổ Ma, hiến máu mượn ba trăm ma hồn để phong sát Vương Lâm. Vương Lâm nhận ra các ma hồn giống Cổ Ma Tháp Già nhưng bị Cổ Thần lực phong ấn, bèn phát tiếng rống Cổ Thần khiến ma phong tan vỡ. Từ dấu vết này, hắn suy ra Tham Lang từng đến một nơi đặc biệt chứa các pháp bảo kia và mừng rỡ tiến về phía Tham Lang."},{"chuong":1299,"tieuDe":"Không Phải Sợ!","tomTat":"Tham Lang khiếp sợ Vương Lâm, xem hắn là khắc tinh chuyên khắc pháp bảo của mình, nên lại dùng cách ném bình ngọc màu tím để đánh lạc hướng rồi bỏ chạy. Vương Lâm không vội truy sát mà thu lấy bình ngọc, sau đó dùng súc địa thành thốn tiếp tục đuổi theo và coi Tham Lang như phúc tinh trên đường tu đạo. Tham Lang lấy cây quạt lớn màu vàng khắc dị thú, khiến mãnh thú hóa ra quấn quanh hắn và tăng tốc bỏ chạy trong tinh không. Trong lúc truy đuổi, Vương Lâm nhận ra pháp bảo của Tham Lang đều liên quan tới ba đại cổ tộc, từ đó đoán ra nơi phát sinh cơ duyên của hắn là cơ hội lớn đối với mình. Bị dồn ép và đau xót vì mất quá nhiều bảo vật, Tham Lang quay lại liều mạng, mở khe không gian thi triển Yêu Lang hàng thế, phạt diệt đạo thiên, dẫn yêu khí Cổ Yêu gọi ra yêu lang vạn trượng. Vương Lâm hóa thành Cổ Thần lục tinh gần ngàn trượng, ngưng huyết kiếm trăm trượng chém đôi yêu lang, phá thế phản kích của Tham Lang. Khi Tham Lang hoảng sợ lấy pho tượng khắc gỗ tàn phá là pháp bảo cực mạnh, Vương Lâm dùng Định khiến hắn không thể cử động, rồi nói chỉ cần trả lời vài vấn đề thì sẽ không giết."},{"chuong":1300,"tieuDe":"Thân Phận Và Lai Lịch Pho Tượng","tomTat":"Vương Lâm dùng Định thân thuật khống chế Tham Lang, thản nhiên lấy đi pho tượng bị tàn phá mà đối phương xem như pháp bảo trọng yếu, còn cố ý nhắc lại chuyện Tham Lang từng nhiều lần “tặng” bảo vật cho mình. Khi quan sát pho tượng, hắn bị một luồng lực lượng khó lường đánh thẳng vào tâm thần, thấy tinh không sụp đổ, hư vô mở ra và một đại lục mênh mông vượt xa nhận thức hiện tại; sau đó hắn càng cảm nhận được uy nghiêm của pho tượng vượt xa cả tượng Thanh Lâm, đủ khiến tu sĩ bước thứ ba cũng phải run sợ. Bị ép hỏi, Tham Lang khai rằng pho tượng cùng nhiều pháp bảo của hắn đều lấy từ một cổ mộ kỳ dị mà hắn vô tình tiến vào qua dòng xoáy ở rìa La Thiên Tinh Vực sau khi thoát khỏi Vọng Nguyệt. Trong cổ mộ ấy có không gian loạn lưu, cự thạch, sương mù, đầu lâu khổng lồ có tinh điểm ở mi tâm, những pháp bảo đặt như vật tế bái, cùng một khu rừng khô héo vô biên nơi hắn tìm được Vạn Cổ Mộc Linh, Cổ Tức Diệp và cuối cùng là pho tượng bí ẩn. Tham Lang kể rằng ngay khi chạm vào pho tượng, một dòng xoáy khác mở ra đưa hắn ra ngoài Phong Giới Đại Trận, khiến Vương Lâm nhận ra vận may của hắn quả thật quái dị như thể luôn có cơ duyên tự tìm tới. Sau khi Định thân thuật hết hiệu lực, Tham Lang định bỏ chạy nhưng bị Vương Lâm bắt lại sưu ký ức bằng thần thức và bổn nguyên lôi đình để xác nhận lời khai, rồi được tha mạng vì Vương Lâm xem hắn là phúc tinh không nên giết. Trở về động phủ, Tham Lang mới phát hiện mùi thối do Vọng Nguyệt để lại đã biến mất, hiểu rằng Vương Lâm đã lấy cách này để đổi lấy pháp bảo chứ không hoàn toàn chiếm đoạt không công. Sau đó Vương Lâm trở lại tu chân tinh của Ám Hạt Tộc, chứng kiến Vân Độn tộc vì sợ uy danh của mình mà cúi đầu hầu hạ Chung Đại Hồng, còn Chung Đại Hồng lập tức bỏ vẻ cáo mượn oai hùm để nịnh nọt nghênh đón chủ nhân."},{"chuong":1301,"tieuDe":"Lừa Đảo","tomTat":"Vân Độn tộc không dám rời tu chân tinh khi chưa được Vương Lâm đồng ý, còn Ám Hạt Tộc nhờ quan hệ với hắn mà giữ địa vị cao nhất quanh động phủ mới lập. Vương Lâm trở về liền tạo một động phủ khổng lồ, bố trí nhiều tầng cấm chế để bế quan và suy tính bước tiếp theo. Hắn nhớ lời sứ giả đại đế về kỳ tuyển chọn lại trưởng lão Lạc Sinh hội sau ba tháng, rồi xác định trọng tâm là lợi dụng sự kiện này để đạt mục đích với Hỏa Tước tộc. Ở ngoài vùng đất Điên Lạc, ba tộc nhân Hỏa Tước tộc đang mang máu trong đan dược về tộc nghiên cứu; Vương Lâm thông qua liên hệ huyết mạch cảm ứng vị trí, tin rằng giọt máu chứa tia bổn nguyên sẽ gây sóng gió và giúp hắn thu hỏa bổn nguyên. Sau đó hắn mở không gian trữ vật, gọi Hứa Lập Quốc và Lưu Kim Bưu ra để chuẩn bị bước hai. Bị Vương Lâm ép, Lưu Kim Bưu từ chỗ viện cớ mất ngọc bội liền bộc lộ thuật lừa gạt thật sự, trình bày ba cảnh giới lừa người, lừa mình và phản phác quy chân. Trước sự chế nhạo của Hứa Lập Quốc, Kim Bưu nâng lừa đảo thành một con đường cầu đạo, tuyên bố nếu ba nghìn đại đạo không có lừa đảo thì hắn sẽ tự sáng chế đạo ngoài ba nghìn đại đạo, khiến cả Vương Lâm cũng chấn động."},{"chuong":1302,"tieuDe":"Chu Tước Đời Thứ Sáu","tomTat":"Lưu Kim Bưu giải thích đạo lừa đảo của mình đã tiến tới mức tự lừa gạt bản thân, khiến ký ức và nguyên thần cũng bị biến đổi, còn việc mất ngọc bội lại trở thành cơ hội niết bàn. Vương Lâm nhìn ra giá trị của hắn, hứa trả tự do và cho cơ duyên nếu hắn hoàn thành nhiệm vụ lừa gạt một bộ tộc. Bằng hỏa diễm màu lam từ mắt trái, Vương Lâm cấy ký ức mới cho Lưu Kim Bưu, khiến hắn hoàn toàn tin mình là Chu Tước đời thứ sáu của Chu Tước Thánh Tông. Hứa Lập Quốc được lệnh hầu hạ và nghe theo thân phận giả này, rồi cùng Lưu Kim Bưu rời động phủ để trở thành mồi câu nhằm vào Hỏa Tước tộc. Sau đó Vương Lâm lấy pho tượng đoạt từ Tham Lang ra nghiên cứu, đồng thời nhớ lại hai tọa độ quan trọng trong ký ức Tham Lang: dòng xoáy gần hàng rào giới nội ở La Thiên và nơi Tham Lang rời cổ mộ tại Thái Cổ Tinh Thần. Khi Vương Lâm gọi Ngân y nữ tử ra nhận diện pho tượng, nàng vừa nhìn thấy đã sững người, đồng tử co rút rồi hét lên thê lương."},{"chuong":1303,"tieuDe":"Lại Là Bảy Màu!","tomTat":"Vương Lâm lấy pho tượng bí ẩn ra hỏi ngân y nữ tử, không ngờ nàng vừa nhìn thấy đã sợ hãi đến gần như sụp đổ, liên tục phủ nhận mình đã mở một cánh cửa nào đó và nhắc tới những người đã chết như Đào Vân, Tử Lạc. Khi hắn truy hỏi thân phận của người trong pho tượng, trong cơ thể nàng bộc phát thanh khí quỷ dị, thần trí trở nên lạnh lùng và đánh ra một chưởng khiến cả tu chân tinh chấn động, bầu trời nứt ra khe lớn. Vương Lâm nhận ra thanh khí này không thuộc bất cứ hệ lực lượng quen thuộc nào, phải dùng lôi đồ, huyết kiếm và nhiều thủ đoạn mới phá được chưởng ấn, sau đó cưỡng ép giữ lại một luồng thanh khí đang muốn bay về khe trời. Hắn thi triển Sưu thần thuật lên ngân y nữ tử, bị thanh quang trong thức hải nàng phản chấn nhưng vẫn nhìn thấy sâu trong sương xanh có một trung niên áo bảy màu giống hệt pho tượng, thân ảnh này là do một đạo phong ấn biến thành. Vương Lâm thoáng liên hệ người đó với Chưởng Tôn rồi tự bác bỏ, sau đó xâu chuỗi Thiên Vận Tử, Chưởng Tôn, Thất Thải Giới, Thất Thải Thần Không Đinh cùng thanh khí, cảm thấy sau hai chữ bảy màu ẩn giấu một bí mật cực lớn. Tạm gác chuyện pho tượng, hắn bắt đầu kiểm kê pháp bảo đoạt được từ Tham Lang, giữ chín mươi chín phi kiếm Cổ Yêu cho phân thân thứ hai, luyện Hộ cốt Thạch Bi để nhận thần thông Tổ Hồn trợ giúp và dung hợp Thiên Hoàng Lô vào tinh điểm Cổ Thần đầu tiên. Cuối cùng, khi xem Vụ Ma Thương và Ma Hồn Bình, Vương Lâm nảy ra ý định dùng ma hồn điều khiển pháp bảo Cổ Ma, thậm chí nếu có cơ hội sẽ đoạt xá một thân thể Cổ Ma để tạo thành phân thân thứ ba."},{"chuong":1304,"tieuDe":"Gió Nổi","tomTat":"Tại động phủ ở Ám Hạt Tộc, Vương Lâm bắt đầu luyện hóa Ma Hồn bình, khống chế sương đen và ma hồn Cổ Ma phun ra từ trong bình. Hắn thi triển Đạo thuật Dung của Lam Mộng Đạo Tôn suốt bảy ngày để dung hợp ma hồn thành kén, rồi dùng máu chứa bổn nguyên lực và máu Cổ Thần huyết luyện khi kén phản kháng. Vương Lâm tiếp tục rót nguyên lực vào Ma Hồn bình, nhận ra trong bình có ba nghìn hồn phách Cổ Ma và muốn dung hợp chúng thành hồn phách Cổ Ma của riêng mình. Cùng lúc đó tại vùng đất Điên Lạc, một tinh cầu hoang dã bộc phát lam hỏa khiến hỏa tu toàn vùng chấn động, trong đó có trưởng lão Hỏa Tước tộc từng giao dịch với Vương Lâm. Trưởng lão dẫn tộc nhân đến điều tra nhưng không tìm được vật gì, chỉ cảm nhận được khí tức bổn nguyên giống trong hồn đan. Ba tộc nhân Hỏa Tước tộc hộ tống một vật từ Điên Lạc trở về chủ tinh Hỏa Tước; tộc trưởng nhận ra đó là giọt máu có bổn nguyên nên vào thánh địa cầu kiến lão tổ. Lão tổ Hỏa Tước tộc trong biển lửa tím xác nhận giọt máu là máu Chu Tước có bổn nguyên, lập tức ra lệnh toàn tộc không tiếc giá nào tới Điên Lạc truy tìm nguồn gốc và cảnh giác khả năng có âm mưu."},{"chuong":1305,"tieuDe":"Sóng Dâng","tomTat":"Khi còn sáu ngày tới kỳ tuyển chọn trưởng lão Lạc Sinh hội, ma vụ quanh tu chân tinh Ám Hạt Tộc đột nhiên co rút, toàn bộ ma khí hóa thành dòng xoáy lao vào động phủ nơi Vương Lâm bế quan. Trong động phủ, ma hồn đỏ sậm do Vương Lâm tạo ra hút sạch ma khí rồi sinh ý phản nghịch, định thôn phệ hắn nhưng bị quát lui, truy hồi bằng ấn ký và cưỡng ép dung nhập Vụ Ma Thương. Vụ Ma Thương vì vậy như sinh linh hồn, bộc phát khí tức cực mạnh và hóa hắc mãng che trời, khiến Ám Hạt Tộc cùng Vân Độn tộc kinh hãi, còn Chung Đại Hồng quỳ xuống hô mừng chủ nhân. Vương Lâm nhận ra phân thân ma hồn tuy chưa đại thành nhưng đã có cơ sở, sau đó suy tính việc hợp nhất ba thân thể thần, ma, yêu để phản tổ thành cổ và lấy ra phiến lá cây khô vàng cùng thụ nhân bị phong ấn. Chương chuyển sang giới thiệu Đại đế tinh trong vùng đất Điên Lạc, thánh địa kiêm động phủ của đại đế, nơi chỉ mở thông đạo trong kỳ tuyển chọn trưởng lão Lạc Sinh hội. Vương Lâm cùng Ám Hạt Tộc và Vân Độn tộc lên đường tới Đại đế tinh, trong khi Vân Lạc, nam tử trung niên, Lam Mộng Đạo Tôn, Liêu Thiên Cửu và Vọng Nguyệt chở lão giả áo trắng cùng ba người hầu cũng lần lượt xuất hiện trên các tuyến hướng về biến cố lớn."},{"chuong":1306,"tieuDe":"Thình Thịch","tomTat":"Trước ngày tuyển chọn trưởng lão Lạc Sinh hội, Vương Lâm được Ám Hạt Tộc và Vân Độn tộc hộ tống tới ngoài Đại đế tinh, nơi bị sương mù, khe nứt, từ lực và lực giằng xé bao phủ. Trong lúc các tiểu tộc Điên Lạc tụ tập chờ thông đạo mở, đại trưởng lão Hồn Xà tộc khơi chuyện Vân Độn tộc từng mời Tham Lang làm cung phụng, kéo sự chú ý của đám đông về phía Vân Độn tộc và Ám Hạt Tộc. Tộc trưởng Hà tộc, cũng là trưởng lão thứ mười ba Lạc Sinh hội, muốn lập uy nên ép Ám Hạt Tộc quỳ, rồi chỉ thẳng Vương Lâm bắt quỳ vì lầm tưởng hắn là người thay mặt Tham Lang. Vương Lâm vẫn bình thản hỏi ngược, trong khi tộc trưởng Ám Hạt và Vân Độn lộ vẻ châm chọc khiến Hà tộc bắt đầu bất an. Ngay sau đó, tộc trưởng Long Giáp Tộc mới dẫn hơn một ngàn tộc nhân tới và công khai bái kiến Vương Lâm, làm toàn trường biến sắc. Khi thông đạo Đại đế tinh mở ra, sứ giả đại đế dẫn đầu mười tu sĩ xuất hiện và đi thẳng về phía Vương Lâm, khiến trưởng lão thứ mười ba kinh hãi đến mức tim đập thình thịch."},{"chuong":1307,"tieuDe":"Hoàng Mao Nha Đầu","tomTat":"Sứ giả đại đế cùng các tu sĩ từ thông đạo đi ra cung kính bái kiến Vương Lâm là thiếu đế, khiến mấy vạn tu sĩ quanh Đại đế tinh chấn động vì danh tính thiếu đế thứ ba lần đầu được công khai. Những kẻ vừa đối đầu hoặc dẫn họa về phía hắn lập tức hoảng sợ, nhất là nam tử Hồn Xà tộc, tộc trưởng Hà tộc kiêm trưởng lão thứ mười ba Lạc Sinh hội và tộc trưởng Vân Độn tộc. Vương Lâm không giết người nhưng ra tay xử phạt nặng: hủy tư cách dự tuyển trưởng lão của Hồn Xà tộc, tước vị trưởng lão Lạc Sinh hội của tộc trưởng Hà tộc rồi đày quỳ trăm năm tại tu chân tinh Ám Hạt Tộc, đồng thời buộc tộc trưởng Vân Độn tộc tự phế một tay. Sau đó hắn tiến vào thông đạo Đại đế tinh, cảm nhận lực giằng xé và từ lực hút nguyên lực bên trong. Một đồ hình bát giác khổng lồ chở Vân Lạc của Trường Tôn hội và Tư Mặc Tử lao tới; Vân Lạc nói mình thay mặt Trường Tôn hội tới bái kiến đại đế và xem tuyển chọn trưởng lão. Tư Mặc Tử thấy Vương Lâm thì sát khí bùng lên, chửi mắng và đòi chiến, nhưng bị Vương Lâm gọi là bại tướng và khiêu khích vào sương mù từ lực tự hủy tu vi. Cuối chương, Vương Lâm bác cách Vân Lạc gọi mình là đạo hữu, lạnh lùng mắng nàng không phân lớn nhỏ và không biết lễ với tiền bối."},{"chuong":1308,"tieuDe":"Cổ Hồn Cấm","tomTat":"Nữ tử Trường Tôn hội tiếp tục hỏi tên Vương Lâm, khiến hắn cảnh giác vì Đại ti thuật của Trường Tôn hội quá quỷ dị và làm hắn nhớ tới Thiên Vận Tử. Vương Lâm chỉ báo danh Hứa Mộc, nên nữ tử dù âm thầm niệm tên cũng không thể thi triển Danh khôi ti thuật vì đó không phải tên thật do hắn tự thừa nhận. Trên đường vào Đại đế tinh, Vương Lâm tiếp tục thử thái độ đại đế bằng cách yêu cầu cho tộc trưởng Ám Hạt Tộc thành trưởng lão Lạc Sinh hội; sứ giả truyền âm rồi chấp thuận, khiến hắn nhận ra đại đế không coi trọng Lạc Sinh hội. Sau khi đặt chân lên Đại đế tinh, hắn phát hiện tinh cầu này không có tầng cương phong, không có núi, toàn bình nguyên phủ thực vật lá lớn, phía tây bắc có trường đấu cấm chế dùng cho tuyển chọn ngày mai. Sứ giả cáo lui, còn Vương Lâm tự đến dò xét trường đấu, chạm vào cấm chế thì bị phản chấn và cảm nhận khí tức hồn phách tang thương. Hắn dùng Lôi đồ từ ấn ký lôi đình mắt phải ép cấm chế hiện hình thành một con rùa xám khổng lồ ngàn dặm. Sau khi thu Lôi đồ, Vương Lâm xác nhận đây là Cổ Hồn cấm, một trong tứ đại cấm đã thất truyền, có liên quan tới mãnh thú và dùng hồn phách cùng thân thể mãnh thú hóa thành cấm chế."},{"chuong":1309,"tieuDe":"Hồ Tâm Tàng Nguyệt","tomTat":"Sau khi con rùa cấm chế khổng lồ tiêu tan, Vương Lâm nhận ra Đại đế tinh có Cổ Hồn cấm và lập tức liên hệ nó với cơ hội gom đủ tứ đại cấm để chạm tới bốn nguyên cấm chế. Niềm kích động của hắn nhanh chóng chuyển thành cảnh giác, vì đại đế có thể đã dự liệu trước phản ứng của hắn và bản thân Đại đế tinh cũng có quá nhiều điểm quỷ dị. Vương Lâm hạ xuống nhiều khu vực lấy bùn đất, nhớ lại trải nghiệm Thiên Nghịch mở ra rồi dùng Lưu Nguyệt truy tìm dấu vết năm tháng, từ đó suy đoán bùn đất trên tinh cầu gần như đồng thời sinh ra và cả nơi này có thể do thần thông tạo thành. Trong lúc suy nghĩ về Vân Lạc, Tư Mặc Tử và Trường Tôn hội, hắn vẫn tính tới việc mượn thế lực của đại đế làm trợ lực cho mình. Khi ngồi trên một chiếc lá lớn, Vương Lâm phát hiện lá cây dường như hút đi một tia nguyên lực yếu ớt, khiến hắn kinh hãi rời khỏi đó để quan sát tiếp. Đến hoàng hôn, hắn gặp một lão giả mặc bạch y câu cá bên hồ, ngồi cạnh lão trong im lặng cho tới khi lão cất tiếng hỏi hắn có uống rượu không."},{"chuong":1310,"tieuDe":"Câu Rồng","tomTat":"Vương Lâm cầm bầu bên cạnh uống một ngụm lớn, ban đầu tưởng là rượu nhưng lập tức cảm thấy như nuốt hỏa long, nguyên lực tăng thêm một tia và hỏa bổn nguyên trong cơ thể nồng đậm hơn. Lão giả bên hồ nói đó không phải rượu mà là máu, rồi kéo dây câu bạc khiến mặt hồ nổi sóng và câu lên một Viêm long đỏ dài ngàn trượng. Uy áp của Viêm long khiến Vương Lâm tái mặt, nhận ra nó có lực áp bách ngang tu sĩ bước thứ ba và không kém cảm giác Thủy Đạo Tử từng gây ra. Lão giả dùng hỏa vụ vô hình cùng hư ảnh Chu Tước khổng lồ áp chế Viêm long, hợp lực vào tay trái để xuyên vào chỗ nhô trên đầu rồng lấy máu. Vương Lâm dùng bầu hứng máu, thấy bình thuốc của mình bị hòa tan nên hút luôn phần máu còn lại vào miệng để khỏi lãng phí. Sau khi thả Viêm long về hồ, lão giả vui vẻ khen hắn, kiểm tra thân thể rồi xác nhận hắn là tộc nhân Chu Tước đời thứ sáu, đồng thời nhận ra thân thể Cổ Thần của hắn. Lão nhắc Chu Tước đời thứ tư phong lưu nên không tu được thần thông của mình, còn Vương Lâm lạnh lùng có lẽ thích hợp hơn, mở ra khả năng truyền thừa mới."},{"chuong":1311,"tieuDe":"Chu Tước Lão Tổ","tomTat":"Chu Tước đời thứ hai kiểm tra thiên linh Vương Lâm và lần lượt phát hiện năm đạo bổn nguyên: hỏa, lôi, sinh tử, nhân quả và chân giả, khiến ông từ tiếc nuối chuyển sang kinh hãi rồi mừng rỡ. Vương Lâm sau một đêm hấp thu máu rồng tỉnh lại, lực hỏa diễm tăng mạnh nhưng vẫn còn thiếu một tia để đạt lần thức tỉnh thứ tư của Chu Tước. Khi Vương Lâm bái kiến, lão giả phủ nhận mình là đời đầu hay đời thứ tư và xác nhận bản thân là Chu Tước đời thứ hai, đồng thời giải thích Điên Lạc đại đế trong tộc được gọi là Chu Tước lão tổ. Ông cho biết mình và Chu Tước đời thứ tư đều là thiếu đế, còn Chu Tước lão tổ là một trong tứ đại chiến tướng dưới trướng viễn cổ tiên tôn. Sau đó, ông khuyên Vương Lâm dùng Tư Mặc Tử làm đối tượng lập uy trước các tu sĩ bước thứ ba tới dự tuyển chọn trưởng lão Lạc Sinh hội. Vì thần thông riêng không hợp với Vương Lâm, ông quyết định truyền một bí thuật vận lực lấy từ mạch Huyền Vũ, mở đầu bằng cách biểu diễn bên mặt hồ."},{"chuong":1312,"tieuDe":"Dùng Lực Chứng Đạo","tomTat":"Lão Chu Tước biểu diễn một chưởng lên hồ nước, khiến một tầng nước tan thành hơi nước rồi để Vương Lâm tự quan sát thâm ý bên trong. Vương Lâm tự nhấn tay xuống mặt hồ, cảm nhận phản lực rất yếu của nước và từ đó liên hệ tới đạo lý nước nhỏ giọt xuyên đá. Hắn suy ra khi một quyền đánh ra, ngoài lực lượng bản thân còn có thể mượn lực phản chấn của vật bị công kích để tăng uy lực và khiến hình thái vật chất sụp đổ biến đổi. Lão Chu Tước kinh hãi trước ngộ tính của hắn, đồng thời nghĩ tới khả năng nếu Vương Lâm học xong Cổ Hồn cấm thì có thể sinh ra bổn nguyên cấm chế. Vương Lâm nhận ra bí thuật này đặc biệt quan trọng với thân Cổ Thần và tự thấy mình trước đây kém Thác Sâm xa về cách vận dụng lực lượng. Lão Chu Tước giữ vẻ cao thâm, tuyên bố bí thuật đã học xong rồi dùng hư hỏa cuốn Vương Lâm tới trường đấu phía tây bắc để thí luyện. Tại trường đấu ngàn dặm, hai tu sĩ đang tranh vị trí trưởng lão trước mấy vạn người, còn Tư Mặc Tử, Vân Lạc, đôi phụ tử lam quang, thiếu niên thanh sam và lão già áo da thú đều ở các khu vực trên không không ai dám tới gần. Khi Lão Chu Tước và Vương Lâm đến, các cường giả này đồng loạt biến sắc ngẩng đầu."},{"chuong":1313,"tieuDe":"Lão Chu Tước Bao Che","tomTat":"Lão Chu Tước xuất hiện trước đông đảo cường giả trên Đại đế tinh và đưa Vương Lâm ra mắt, khiến Tư Mặc Tử lộ sát khí, Lý Thiến Mai nhìn hắn đầy mê man, còn Diệu Âm đạo tôn âm thầm quan sát. Vương Lâm hành lễ với Lam Mộng đạo tôn, làm lão Chu Tước bất ngờ nhận ra giữa hai người vốn đã có duyên cũ. Ngay sau đó, lão Chu Tước công khai ra mặt cho Vương Lâm, dùng hư hỏa đánh trọng thương Tư Mặc Tử rồi liên tiếp tát hắn, mặc cho đối phương thuộc Trường Tôn hội; Vân Lạc đại ti muốn can thiệp cũng bị lão quát nạt đến im lặng. Qua việc này, thái độ bao che nổi tiếng của Chu Tước nhất tộc được bộc lộ rõ, còn Vương Lâm âm thầm ghi nhận ân tình của lão như từng ghi nhớ Thanh Thủy và Chu Tước lão Thánh Hoàng. Trước toàn trường, lão Chu Tước tuyên bố Vương Lâm sẽ tham gia thí luyện thiếu đế thứ ba của vùng đất Điên Lạc, nếu thành công thì kẻ địch của hắn cũng là kẻ địch của lão và cả Điên Lạc. Sau đó lão giới thiệu các đại năng có mặt, gồm Diệu Âm đạo tôn thuộc Thái Cổ Ngũ Tôn và Thái Hoang Công nổi danh độc công, người còn tặng Vương Lâm nửa đoạn móng tay chứa độc làm vật phòng thân. Khi tuyển chọn trưởng lão Lạc Sinh hội kết thúc, lão Chu Tước chính thức mở thiếu đế thí luyện, khiến trường đấu ngàn dặm chấn động và một cự quy khổng lồ hiện thân, chăm chú nhìn về phía lão."},{"chuong":1314,"tieuDe":"Phù Sinh Nhược Mộng","tomTat":"Lão Chu Tước nghiêm túc hô dâng hương, khiến ba cây hương khổng lồ hiện ra trên lưng cự quy và công bố thí luyện thiếu đế của vùng đất Điên Lạc gồm ba huyễn giới Thiên, Địa, Nhân. Ông nói người thí luyện phải đưa hồn vào hương, kéo chậm tốc độ cháy và thoát ra trước khi hương tàn, nếu không hồn phách sẽ bị thiêu đốt mà chết. Vương Lâm nghe lịch sử chỉ có hai người từng thành công nhưng vẫn bình tĩnh nhận lời, rồi được đưa tới cây hương thứ nhất. Trong khi đó, Tư Mặc Tử ngầm ôm sát ý, Vân Lạc âm thầm thôi diễn, Diệu Âm đạo tôn cân nhắc tin Vương Lâm là chủ nhân phong giới chưa chết, còn Lam Mộng đạo tôn dao động vì trách nhiệm với Thái Cổ Tinh Thần và những ràng buộc gia đình. Trước sự quan sát của mấy vạn tu sĩ, Vương Lâm chạm vào cây hương, thân thể bất động và hồn phách tiến vào Nhân giới huyễn cảnh. Hắn thấy mình đứng trên một cây cầu giữa thành trì phàm nhân mờ ảo như mộng, rồi nhìn thấy một thanh niên uống rượu trên thuyền có dung mạo vô cùng quen thuộc, khiến hắn chấn động."},{"chuong":1315,"tieuDe":"Nhược Hồn Bi","tomTat":"Trong huyễn giới cửa Nhân của thí luyện, Vương Lâm đứng trên cầu đá gặp một thanh niên phàm nhân dung mạo giống hệt mình trên thuyền. Hắn lên thuyền đối ẩm, trầm tư uống rượu, rồi tự nói ra lai lịch phụ thân Vương Thiên Thủy làm thợ mộc, mẫu thân Chu Anh Tố người Chu gia trang. Giác ngộ cửa Nhân không phải vấn đạo mà là tâm ma: thanh niên kia là hư hồn nhân sinh do sự chán nản tu đạo trong lòng hắn sinh ra, đại diện cuộc đời phàm tục hắn đã không chọn. Biết có thể đốt cây hương ngay lập tức nhưng muốn đi nhìn người thân và Lý Mộ Uyển thêm một lần. Đứng trên Hằng Nhạc phái nhìn sơn thôn, rơi lệ rồi gạt đi. Bên ngoài trên Đại Đế tinh, thân thể hắn bất động hơn một canh giờ, hai hàng lệ trong suốt chảy xuống. Lão Chu Tước lo lắng, Tư Mặc Tử cười nhạt gọi hắn là tiểu tạp chủng, Vân Lạc bắt quyết tính toán, Lam Mộng đạo tôn giải thích hiện tượng hồn về quê cũ. Cuối chương, cảnh chuyển sang Lạc Hà môn trong Hỏa Phần quốc: Lý Mộ Uyển dưới hình dạng thiếu nữ đang luyện đan thất bại, được sư tôn sai đi lấy Thủy Nguyệt thảo."},{"chuong":1316,"tieuDe":"Ta Không Muốn","tomTat":"Trong Nhân giới thí luyện, một thiếu nữ áo vàng của Lạc Hà môn đi hái thảo dược, than luyện đan khó và nhắc tới ca ca có thiên tư hơn mình. Nàng phát hiện thú nhỏ bị thương, dùng thảo dược cứu chữa nhưng không đủ sức cứu nó; Vương Lâm đứng sau nhận ra nàng chính là Lý Mộ Uyển, rồi dùng bạch quang chữa lành con thú. Hắn đưa nàng lên đỉnh núi nơi mình ở, khiến nàng vừa nghi hắn là cao nhân lánh đời vừa sợ hãi tìm cớ rời đi. Vương Lâm chờ nàng bốn ngày, nhớ lại năm xưa nàng từng chờ hắn ở Vân Thiên Tông; ngày thứ năm, Lý Mộ Uyển quay lại nhờ hắn cứu thêm một con thú nhỏ khác. Sau khi nàng rời đi, thiên địa Nhân giới biến sắc, lão Chu Tước từ Đại Đế tinh truyền âm thúc Vương Lâm dùng hỏa diễm trong hồn thiêu rụi cả thế giới để hoàn thành cây hương thứ nhất. Vương Lâm thẳng thừng nói không muốn, không chấp nhận đốt phàm niệm và thế giới có Lý Mộ Uyển để đổi lấy bất diệt hồn hỏa cho lần thức tỉnh Chu Tước thứ tư. Hắn tuyên bố sẽ nghịch đạo, lấy chấp niệm bản thân hóa thành nghiệp hỏa để đốt nghiệp chướng luân hồi. Bên ngoài, lão Chu Tước tát Tư Mặc Tử vì lời châm chọc, rồi thầm nhận định con đường nghiệp hỏa nhập hồn cực kỳ gian nan nhưng nếu Vương Lâm thành công thì sẽ trở thành nhân vật đệ nhất của Chu Tước tộc."},{"chuong":1317,"tieuDe":"Nghiệp Hỏa Hồn Trung Khởi","tomTat":"Trong Nhân phương giới, dòng xoáy trên trời mà chỉ Vương Lâm cảm nhận được sụp đổ rồi tiêu tán, còn hắn hiểu rằng muốn khiến Chu Tước thức tỉnh lần thứ tư thì phải lấy chấp niệm nhóm nghiệp chướng luân hồi để hóa thành nghiệp hỏa. Chương hé lộ hư hỏa là cảnh giới sau thực hỏa, có thể lấy dao động tâm tình của sinh linh làm thần thông giết địch, thậm chí tiến thêm thành đạo hỏa để mở Không môn. Vương Lâm không muốn đốt hủy Nhân giới nên chọn tự thiêu hồn phách bằng lửa lam, trong khi Lý Mộ Uyển thường lên núi gặp hắn khiến chấp niệm càng sâu và ngọn lửa càng dữ dội. Lão Chu Tước nhiều lần khuyên hắn bỏ cuộc, cảnh báo rằng khi nghiệp hỏa thật sự xuất hiện thì Cửu chuyển nghiệp kiếp mới bắt đầu và hồn phách có thể bị hủy diệt. Thấy Vương Lâm không chịu buông bỏ, lão quyết phóng biển lửa hủy diệt Nhân giới để cứu hắn, đúng lúc Lý Mộ Uyển xuất hiện trên đỉnh núi. Vương Lâm tỉnh lại trong thống khổ, ôm nàng và lấy lưng chắn biển lửa, nói rằng cả đời tu đạo chỉ vì một người, dù nàng là hư ảo cũng không muốn làm tổn thương. Sau lời ấy, tia nghiệp hỏa màu đen bùng lên trong hồn phách hắn, lan khắp thân thể và bắt đầu hủy diệt hồn phách lẫn thân xác. Lý Mộ Uyển bị lời nói của hắn làm chấn động, kinh ngạc nhìn Vương Lâm và hỏi hắn là ai."},{"chuong":1318,"tieuDe":"Lang Yên Thương Hương Nhiên","tomTat":"Ảo ảnh ngàn năm trước khép lại khi Vương Lâm ôm Lý Mộ Uyển già đi rồi tan mất, còn chính hồn thể hắn cũng bị nghiệp hỏa đen thiêu đến gần tiêu tán. Trong thời khắc ấy, hắn tuyên bố lấy chấp niệm nhập đạo, lấy niệm tạo nghiệp, hóa nghiệp chướng luân hồi và coi đó là thiên đạo của riêng mình. Hồn phách Vương Lâm sau đó hóa thành Chu Tước màu đen như Hắc Phượng Hoàng, tiếng kêu vang xuyên khỏi Nhân phương giới tới cây hương thứ nhất trên Đại đế tinh, khiến Lam Mộng đạo tôn, Tư Mặc Tử, Vân Lạc và Chu Tước đời thứ hai đều chấn động. Từ Nhân phương giới, hắn dẫn biển nghiệp hỏa đen dồn thành cột lửa đánh lên thiên không để đốt Nhân phương hương, làm cây hương bên ngoài bốc khói đen rồi cháy dữ dội trước mắt mấy vạn tu sĩ. Vân Lạc bị cắt đứt thôi diễn, còn Chu Tước đời thứ hai nhận ra Vương Lâm đã hóa Chu Tước trong nghiệp hỏa và sắp đối mặt cửa ải Cửu chuyển hỏa kiếp. Cuối chương, Vương Lâm đứng trên lưng Chu Tước đen, nói tên thật với Lý Mộ Uyển rồi nghênh tiếp Cửu chuyển nghiệp kiếp khi lửa đen quanh thân chuyển thành đỏ như máu và cây hương thứ nhất tiếp tục bị thiêu cháy."},{"chuong":1319,"tieuDe":"Kinh Biến","tomTat":"Trong Nhân phương giới, Cửu Chuyển Nghiệp Hỏa Kiếp bắt đầu bằng ngọn lửa đỏ của đệ nhất kiếp, thiêu đốt hồn phách Vương Lâm và làm Chu Tước màu đen dưới chân hắn kêu thảm, có nguy cơ bị hóa thành một phần kiếp hỏa. Vương Lâm không chịu khuất phục mà hút toàn bộ lửa đỏ vào hồn phách, khiến cây hương thứ nhất trên Đại đế tinh bùng cháy và khói hóa đỏ. Khi hắn còn chưa luyện hóa xong, Chanh, Hoàng, Lục tam kiếp đồng thời giáng xuống, cho thấy kiếp này là kiếp hủy diệt không chừa đường sống. Bên ngoài, Lão Chu Tước lo lắng, Ti Mặc Tử mừng thầm, Vân Lạc tạm cho rằng Vương Lâm không phải người trong quẻ tổ tiên, còn Lý Thiến Mai cầu xin Lam Mộng Đạo Tôn giúp hắn. Vương Lâm tiếp tục nuốt cả ba loại nghiệp hỏa vào thân, uống cạn bầu máu rồng để kích hỏa đối kháng, đồng thời khí tức Thiên Nghịch châu trong hồn phách dần thức tỉnh. Sau đó hắn tuyên bố Nhân phương giới đã không còn lửa vì bị hắn nuốt hết, lao lên phá bầu trời và nhìn thấy một mặt đất khác đầy hồn phách. Trên Đại đế tinh, Nhân Phương Hương vượt mốc năm nhịp thở của Chu Tước đời thứ tư rồi bất ngờ tắt ngấm ở nhịp thứ bảy, khiến đám đông xôn xao, Lão Chu Tước không tin nổi, Ti Mặc Tử khiếp sợ và Vân Lạc lập tức bấm quyết tính toán lại."},{"chuong":1320,"tieuDe":"Tỉnh Giấc Lần Thứ Tư!","tomTat":"Nhân Phương hương tắt gây chấn động chưa có tiền lệ, ngay sau đó Địa Phương hương tự bốc cháy quỷ dị. Vương Lâm phá bầu trời Nhân Phương giới lao vào Địa Phương giới, bị Cửu Chuyển Nghiệp Kiếp bảy màu thiêu tan hồn phách. Nam tử trung niên trong Địa Phương giới, lão Chu Tước và Lam Mộng đạo tôn đồng thời ra tay cứu viện nhưng đều bị sức mạnh kỳ dị của Thiên Nghịch bức lui. Thiên Nghịch tái hiện sau thời gian dài biến mất, hút toàn bộ lửa bảy màu thành bảy ngọn lửa bất diệt và ngưng luyện hư ảnh Vương Lâm. Hai kiếp cuối đen trắng giáng xuống hoàn chỉnh chín màu. Vương Lâm mở mắt đốt lên nghiệp chướng luân hồi, chín màu lửa dung hợp thành sen lửa chín cánh tại mi tâm, Chu Tước chín màu bay ra phát tiếng kêu đánh dấu lần tỉnh giấc thứ tư. Lão Chu Tước giẫm bắt Viêm long vạn trượng, ép máu tưới Địa Phương hương để trợ lực Vương Lâm từ thực hỏa tiến vào hư hỏa."},{"chuong":1321,"tieuDe":"Chín Màu Hợp Nhất!","tomTat":"Lão Chu Tước trên Đại đế tinh đánh vào đỉnh đầu viêm long lấy toàn bộ viêm huyết tinh hoa truyền vào Địa Phương hương, khởi động đợt hỏa lực đầu tiên cho quá trình thức tỉnh Chu Tước lần thứ tư của Vương Lâm. Trong Địa Phương giới, Vương Lâm ngồi trên hỏa liên chín màu hấp thu hỏa lực, phía sau hắn Chu Tước chín màu giãy giụa như muốn tái sinh. Nam tử trung niên trên ngọn núi trọc lộ thân phận là Chu Tước đời thứ tư, sư phụ của Lỗ Vân, nhận ra khí tức của đồ đệ trên thân Vương Lâm và chủ động phóng hư hỏa tương trợ. Khi viêm huyết cạn, lão Chu Tước ép viêm long phun thêm long huyết thường với số lượng lớn, rồi tự cắn răng xuất hư hỏa bản thân vào Địa Phương hương, liều mạng hết thảy. Viêm long uất ức nhớ lại việc năm xưa bị Chu Tước đời đầu lừa ra khỏi viêm vực nhưng vì lời hứa của Chu Tước đời thứ hai nên dốc sức phun máu. Sau khi bảy màu lần lượt tan, Vương Lâm từ chối nhận thêm trợ giúp và tự dùng đạo thuật dung hòa vạn vật để hòa tan hai màu trắng đen cuối cùng. Chín màu hợp thành một, Chu Tước của hắn lao ra với hư hỏa lưu chuyển trên toàn thân, đánh dấu thức tỉnh Chu Tước lần thứ tư thành công, thực hỏa chính thức nhập hư."},{"chuong":1322,"tieuDe":"Thiên Nghịch Chi Biến!","tomTat":"Chu Tước của Vương Lâm bước vào lần thức tỉnh thứ tư, hấp thu toàn bộ hỏa diễm trong Địa phương giới, hỏa liên chín màu hóa giáp, đạt cực hạn thực hỏa. Đại đế tinh bỗng chấn động và xoay như kim la bàn, khiến mấy vạn tu sĩ kinh hãi. Vân Lạc đại ti đang suy tính thì bị lực lượng bí ẩn phản phệ, tay phải rách nát, nôn máu, đồng thời thấy ảo tượng Thái Cổ Tinh Thần nhuộm máu, Diệu âm đạo tôn và nhiều cường giả chết, Phong Giới Đại Trận sụp đổ, bản thân cũng bị bóng người giết. Sương mù từ lực quanh Đại đế tinh cuộn xuống và bị Địa phương hương hút vào như hố đen. Thiên Nghịch trong cơ thể Vương Lâm tự bộc phát, hiện ở lồng ngực như dòng xoáy, hấp thu toàn bộ sương mù từ lực; trong hồn phách Vương Lâm hiện hình la bàn khổng lồ ngang tinh không với Thiên Nghịch ở trung tâm. Bên ngoài, Đại đế tinh hóa kim la bàn chỉ hướng Tây Nam, bắn u quang xóa mọi vật cản, lao tới Phong Giới Đại Trận và trực tiếp va vào đại trận. Sau cùng Thiên Nghịch phun trả từ lực qua thân Vương Lâm, khiến Chu Tước đang ở ngưỡng chuyển hóa bị đánh sâu vào — toàn bộ thực hỏa tan nát hóa hư hỏa, nhưng hư hỏa phát sinh biến hóa quỷ dị đến mức lão tổ Chu Tước đời đầu chứng kiến cũng phải rung động."},{"chuong":1323,"tieuDe":"Vang Dội Điên Lạc","tomTat":"Hư hỏa mới sinh của Vương Lâm hấp thu từ lực thiên đạo, phá quy luật số lượng cố định của Chu Tước tộc, khiến hắn trở thành người đầu tiên từ cổ chí kim có thể tiếp tục hấp thu hư hỏa. Sương mù từ lực trong thân thể hắn bùng ra phá Địa phương giới, lan khắp bầu trời Đại đế tinh. Địa phương hương nứt dày đặc rồi gãy đổ trước mặt mấy vạn tu sĩ, khiến thí luyện ba hương chỉ còn Thiên phương hương. Vân Lạc hoảng sợ phủ nhận, Tư Mặc Tử sinh kiêng kỵ với Vương Lâm, Diệu Âm đạo tôn công khai tham niệm muốn đoạt Thiên Nghịch, Lam Mộng đạo tôn trầm mặc, lão Chu Tước cười khổ vì thí luyện phá lệ. Thiên Nghịch ẩn đi trong Địa phương giới, Vương Lâm hút Chu Tước hư huyễn vào mắt phải, cơ thể tràn ngập hư hỏa vô hình mang lực lượng diệt thế. Hắn tới ngọn núi trọc gặp Chu Tước đời thứ tư, đưa thi hài Lão Thánh Hoàng Lỗ Vân về bên sư phụ cũ. Chu Tước đời thứ tư đau đớn tiết lộ mình bị người thần bí hạ phong ấn ở Thái Cổ Tinh Thần, hễ rời Địa phương giới sẽ mất tâm thần, và phong ấn cũng có trên Chu Tước đời thứ hai; nếu vùng đất Điên Lạc sụp đổ thì Chu Tước tộc sẽ phát điên mà chết. Khi thân ảnh Vương Lâm biến mất trong Địa phương giới, thân thể hắn dưới Nhân phương hương trên Đại đế tinh mở mắt tỉnh lại."}];
